INSERT IGNORE INTO `pages` (`id`, `category_id`, `title`, `slug`, `content`, `original_file`, `sort_order`, `created_at`) VALUES ('19', '12', 'Fúltol en Moratalla. 2ª Cadete', 'fultol-en-moratalla-2a-cadete-8117', '\n\n<p><b><font size=\"4\"  >2ª CADETE GRUPO III </font></b>\n<font size=\"4\"  ><b>&nbsp;- TEMPORADA 2003 - 2004</b></font></p>\n\n<table border=\"1\" cellpadding=\"0\" cellspacing=\"0\"  id=\"AutoNumber1\"  >\n  <tr>\n    <td  ></td>\n  </tr>\n  <tr>\n    <td >\n    <p align=\"left\" >\n    <font >26ª Jornada</font><p align=\"left\" >\n    <font >MORATALLA - Cehegín (APLAZADO)</font><p >\n    <font >Moratalla se mantiene en la 12ª posición con 18 \n    puntos. <b>FIN DE LA LIGA</b></font></td>\n  </tr>\n  <tr>\n    <td >\n    <p align=\"left\" >\n    <font >25ª Jornada</font><p align=\"left\" >\n    <font >4 Blanca - MORATALLA 1</font><p >\n    <font >Moratalla se mantiene en la 12ª posición con 18 \n    puntos. </font></td>\n  </tr>\n  <tr>\n    <td >\n    <p align=\"left\" >\n    <font >24ª Jornada</font><p align=\"left\" >\n    <font >3 MORATALLA -EF Jumilla 2</font><p >\n    <font >Moratalla sube a la 12ª posición con 18 puntos. </font></td>\n  </tr>\n  <tr>\n    <td >\n    <p align=\"left\" >\n    <font >23ª Jornada</font><p align=\"left\" >\n    <font >5 Almansa - MORATALLA 1</font><p >\n    <font >Moratalla baja a la 13ª posición con 14 puntos. De \n    nuevo los últimos.</font></td>\n  </tr>\n  <tr>\n    <td >\n    <p align=\"left\" >\n    <font >22ª Jornada</font><p align=\"left\" >\n    <font >1 MORATALLA - Jumilla 5</font><p >\n    <font >Moratalla se mantiene la 12ª posición con 14 puntos.</font></td>\n  </tr>\n  <tr>\n    <td >\n    <p align=\"left\" >\n    <font >20ª Jornada</font><p align=\"left\" >\n    <font >0 MORATALLA - Bullas 2</font><p >\n    <font >Moratalla está en la 12ª posición con 14 puntos.</font></td>\n  </tr>\n  <tr>\n    <td >\n    <p align=\"left\" >\n    <font >17ª Jornada</font><p align=\"left\" >\n    <font >MORATALLA - F.B. Almansa</font><p >\n    <font >Moratalla baja a la 13ª posición con 11 puntos. \n    Partido no jugado.</font></td>\n  </tr>\n  <tr>\n    <td >\n    <p align=\"left\" >\n    <font >16ª Jornada</font><p align=\"left\" >\n    <font >3 Base Yecla - MORATALLA 1</font><p >\n    <font >Moratalla baja a la 12ª posición con 11 puntos.</font></td>\n  </tr>\n  <tr>\n    <td >\n    <p align=\"left\" >\n    <font >15ª Jornada</font><p align=\"left\" >\n    <font >4 MORATALLA - Caravaca C.F.</font><p >\n    <font >Moratalla sube a la 11ª posición con 11 puntos.</font></td>\n  </tr>\n  <tr>\n    <td >\n    &nbsp;</td>\n  </tr>\n  <tr>\n    <td >\n    <p align=\"left\" >\n    <font >13ª Jornada</font><p align=\"left\" >\n    <font >3 Cehegín - MORATALLA 0</font><p >\n    <font >Moratalla está en la 13ª posición con 8 puntos. Es el \n    último de la tabla, de los equipos que juegan.</font></td>\n  </tr>\n  <tr>\n    <td >\n    <p align=\"left\" >\n    <font >12ª Jornada</font><p align=\"left\" >\n    <font >1 MORATALLA - Blanca C.F. 2</font><p >\n    <font >Moratalla está en la 12ª posición con 8 puntos.</font></td>\n  </tr>\n</table>\n\n<table CELLSPACING=\"3\" CELLPADDING=\"3\"  border=\"1\"  >\n  <tr>\n    <td  >\n    <div align=\"center\">\n      <center>\n      <table  border=\"1\" border cellspacing=\"1\" >\n        <tr >\n          <td align=\"middle\"  ><b>\n          <font  size=\"2\">Jornada</font></b></td>\n          <td align=\"middle\"  >\n          <font  size=\"2\"><b>Puntos</b></font></td>\n          <td align=\"middle\"  >\n          <font  size=\"2\"><b>Fecha</b></font></td>\n          <td align=\"middle\"  colSpan=\"3\" >\n          <p class=\"resultado2\"><font  size=\"2\"><b>Partido</b></font></td>\n        </tr>\n        <tr>\n          <td align=\"middle\"  ><b>\n          <font  size=\"2\">1</font></b></td>\n          <td align=\"middle\"   >\n          <p class=\"resu\"><font size=\"2\" ><b>3</b></font></td>\n          <td align=\"middle\"  ><b>\n 