INSERT IGNORE INTO `pages` (`id`, `category_id`, `title`, `slug`, `content`, `original_file`, `sort_order`, `created_at`) VALUES ('126', '26', 'banda', 'banda-2931', '\n\n\n\n<p align=\"left\" ><strong>\n<font  size=\"5\" >E</font></strong><font  ><big><big><big><strong><font size=\"5\">XALTACIÓN \nDEL TAMBOR Y EL BOMBO</font></strong></big></big></big></font><strong><font  size=\"5\" >&nbsp; \n&quot;AGRAMÓN \n2004</font><font size=\"5\" >&quot;</font></strong></p> \n\n\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\"  id=\"AutoNumber1\"   border>\n  <tr>\n    <td   valign=\"top\">\n<p align=\"center\">\n<embed   src=\"Images/tamborada_2004.swf\" align=\"left\"></td>\n    <td   colspan=\"2\">\n    <p align=\"center\"><strong >\n<font  size=\"6\" >Fotografías</font></strong></p>\n    <p align=\"center\">\n    <img border=\"0\" src=\"../../../images/cartero.gif\"   align=\"absbottom\"><p align=\"center\">\n    <b><font size=\"2\" ><a href=\"mailto:postmaster@moratalla-murcia.com?subject=Fotos tamborada Agramón 2004\" >Si \n    quieres envi</a></font></b><b><font size=\"2\" ><a href=\"mailto:postmaster@moratalla-murcia.com?subject=Fotos tamborada Agramón 2004\" >ar que ponga alguna de tus fotos envíamela</a>s</font></b></td>\n    <td  >\n    <p align=\"center\" >\n    <a target=\"_blank\" title=\"Monumento al Tambolinero en AGRAMÓN - Inagurado el 19 de Marzo de 2004\" href=\"Images/tamborada2004/monumento101.jpg\">\n    <font >\n    <img border=\"0\" src=\"Images/tamborada2004/monumentoP01.jpg\" alt=\"Monumento al tambolinero\" align=\"left\"  ></font></a></p>\n    <p align=\"center\" >&nbsp;<p align=\"center\" >&nbsp;<p align=\"center\" >&nbsp;<p align=\"center\" >&nbsp;<p align=\"center\" >&nbsp;<p align=\"center\" >&nbsp;<p align=\"center\" >&nbsp;<p align=\"center\" >&nbsp;<p align=\"center\" >&nbsp;<p align=\"center\" >&nbsp;<p align=\"center\" >&nbsp;<p align=\"left\" >&nbsp;<p align=\"left\" >\n    <font ><b>Monumento al \n     \n    </b>\n    </font>\n    <p align=\"left\" >\n    <font ><b>tambolinero</b></font></td>\n  </tr>\n  <tr>\n    <td  >\n<a href=\"Images/tamborada2004/localasociacion102.jpg\" target=\"_blank\">\n<font >\n<img border=\"0\" src=\"Images/tamborada2004/localasociacionP02.jpg\"  ></font></a></td>\n    <td   align=\"center\" colspan=\"2\">\n    <font ><b>&nbsp;&nbsp; \n    Local de la Asociación de  </b>\n    </font>\n    <p><font ><b>Tamboristas de MORATALLA</b></font></td>\n    <td   align=\"right\">\n    <a target=\"_blank\" title=\"Local de la Asociación de Tamboristas de MORATALLA\" href=\"Images/tamborada2004/localasociacion101.jpg\">\n    <font >\n    <img border=\"0\" src=\"Images/tamborada2004/localasociacionP01.jpg\" align=\"left\"  ></font></a></td>\n  </tr>\n  <tr>\n    <td   colspan=\"4\">\n<p  align=\"center\"><b>\n<font size=\"4\" >\nFotos desfile Exaltación del Tambor </font></b></p>\n<p  align=\"center\"><b>\n<font size=\"1\" >(No \nestán todos los que fueron (y fueron muchos), pero si fueron todos los que \nestán)</font></b></p>\n<p  align=\"center\"><font ><b>\nRepresentación de MORATALLA</b></font></td>\n  </tr>\n  <tr>\n    <td  >\n<a href=\"Images/tamborada2004/moratalla110.jpg\" target=\"_blank\">\n<img border=\"0\" src=\"Images/tamborada2004/moratallaP10.jpg\"  ></a></td>\n    <td   align=\"left\">\n    <a href=\"Images/tamborada2004/moratalla109.jpg\" target=\"_blank\">\n    <img border=\"0\" src=\"Images/tamborada2004/moratallaP09.jpg\"  ></a></td>\n    <td   align=\"right\">\n    <a href=\"Images/tamborada2004/moratalla108.jpg\" target=\"_blank\">\n    <img border=\"0\" src=\"Images/tamborada2004/moratallaP08.jpg\"   align=\"left\"></a></td>\n    <td   align=\"right\">\n    <a href=\"Images/tamborada2004/moratalla102.jpg\" target=\"_blank\">\n    <img border=\"0\" src=\"Images/tamborada2004/moratallaP02.jpg\"   align=\"left\"></a></td>\n  </tr>\n  <tr>\n    <td  >\n<a href=\"Images/tamborada2004/moratalla106.jpg\" target=\"_blank\">\n<img border=\"0\" src=\"Images/tam