gaen103.jpg\" target=\"_blank\">\n<img border=\"0\" src=\"Images/tamborada2004/urrea-de-gaenP03.jpg\"  ></a></td>\n    <td   align=\"left\" colspan=\"2\">\n    <p align=\"center\">\n    <a href=\"Images/tamborada2004/urrea-de-gaen101.jpg\" target=\"_blank\">\n    <img border=\"0\" src=\"Images/tamborada2004/urrea-de-gaenP01.jpg\"  ></a></td>\n    <td  >\n    <a href=\"Images/tamborada2004/urrea-de-gaen102.jpg\" target=\"_blank\">\n    <img border=\"0\" src=\"Images/tamborada2004/urrea-de-gaenP02.jpg\"  ></a></td>\n  </tr>\n  <tr>\n    <td  >\n&nbsp;</td>\n    <td   align=\"left\" colspan=\"2\">\n    <p align=\"center\"><font ><b>Por las calles de AGRAMÓN</b></font></td>\n    <td  >\n    &nbsp;</td>\n  </tr>\n  <tr>\n    <td  >\n<a href=\"Images/tamborada2004/calle112.jpg\" target=\"_blank\">\n<img border=\"0\" src=\"Images/tamborada2004/calleP12.jpg\"  ></a></td>\n    <td   align=\"left\">\n    <a href=\"Images/tamborada2004/calle111.jpg\" target=\"_blank\">\n    <img border=\"0\" src=\"Images/tamborada2004/calleP11.jpg\"  ></a></td>\n    <td   align=\"right\">\n    <a href=\"Images/tamborada2004/calle110.jpg\" target=\"_blank\">\n    <img border=\"0\" src=\"Images/tamborada2004/calleP10.jpg\"   align=\"left\"></a></td>\n    <td  >\n    <a href=\"Images/tamborada2004/calle108.jpg\" target=\"_blank\">\n    <img border=\"0\" src=\"Images/tamborada2004/calleP08.jpg\"  ></a></td>\n  </tr>\n  <tr>\n    <td  >\n<a href=\"Images/tamborada2004/calle109.jpg\" target=\"_blank\">\n<img border=\"0\" src=\"Images/tamborada2004/calleP09.jpg\"  ></a></td>\n    <td   align=\"left\">\n    <a href=\"Images/tamborada2004/calle107.jpg\" target=\"_blank\">\n    <img border=\"0\" src=\"Images/tamborada2004/calleP07.jpg\"  ></a></td>\n    <td   align=\"right\">\n    <a href=\"Images/tamborada2004/calle106.jpg\" target=\"_blank\">\n    <img border=\"0\" src=\"Images/tamborada2004/calleP06.jpg\" align=\"left\"  ></a></td>\n    <td  >\n    <a href=\"Images/tamborada2004/calle105.jpg\" target=\"_blank\">\n    <img border=\"0\" src=\"Images/tamborada2004/calleP05.jpg\"  ></a></td>\n  </tr>\n  <tr>\n    <td  >\n<a href=\"Images/tamborada2004/calle104.jpg\" target=\"_blank\">\n<img border=\"0\" src=\"Images/tamborada2004/calleP04.jpg\"  ></a></td>\n    <td   align=\"left\">\n    <a href=\"Images/tamborada2004/calle103.jpg\" target=\"_blank\">\n    <img border=\"0\" src=\"Images/tamborada2004/calleP03.jpg\"  ></a></td>\n    <td   align=\"right\">\n    <a href=\"Images/tamborada2004/calle102.jpg\" target=\"_blank\">\n    <img border=\"0\" src=\"Images/tamborada2004/calleP02.jpg\"   align=\"left\"></a></td>\n    <td  >\n    <a href=\"Images/tamborada2004/calle101.jpg\" target=\"_blank\">\n    <img border=\"0\" src=\"Images/tamborada2004/calleP01.jpg\"  ></a></td>\n  </tr>\n  </table>\n\n<p align=\"left\">\n<span >\n<font  size=\"1\">Moratalla, \nMurcia, Turismo, Trieta, Espana, España,cultura, casas rurales, rural, alojamientos, Pablo \nSalinas Marin,alharabe, benamor, casa cristo, encantada, san jorge, buitre, sabinar, otos, cañada de la cruz, benizar, mazuza, calar de la santa, campo san juan, campo bejar, rogativa, zaen, murtas, nogueras, bajil,\nrupestres, rupestre,pinturas, pintura,mediterraneo,banda, rondalla,naturaleza, montaña, campo, monte, \npueblo, castillo, iglesia, calles, fiestas, musica, Maria del Carmen Rodriguez Rodriguez, \nPablo Salinas Rodriguez, Francisco Salinas Rodriguez,futbol, automovilismo, tamborada,ciclismo, rocasas\n</font></span></span></p>\n</p>\n\n\n\n', 'fotos_exaltación2004.htm', '0', '2026-05-07 23:42:43');
