INSERT IGNORE INTO `pages` (`id`, `category_id`, `title`, `slug`, `content`, `original_file`, `sort_order`, `created_at`) VALUES ('128', '26', 'automovil_2004', 'automovil-2004-6312', '\n\n<table border=\"1\" cellpadding=\"0\" cellspacing=\"0\"  border  id=\"AutoNumber1\" >\n  <tr>\n    <td  >\n    <p >\n    <span >\n    <b>\n    <font size=\"4\"  >Asociación de Tamboristas de Moratalla</font></b></span><font size=\"4\" >&nbsp; </font></p>\n    <p ><font size=\"4\" >\n    <a href=\"Images/tamborada2007_1.jpg\" target=\"_blank\">\n    <img border=\"0\" src=\"Images/tamborada2007_P.jpg\" align=\"left\"  ></a><embed   src=\"Images/Semana_Santa_2004.swf\" align=\"center\"></font></p>\n        </td>\n  </tr>\n  <tr>\n        <td  >\n        <embed   src=\"Images/tamborada_2004.swf\"></td>\n        </tr>\n  <tr>\n    <td  ><font >\n    <embed   src=\"../../../images/atras.swf\" align=\"left\"></font><p>\n    </p>\n    <p></td>\n  </tr>\n</table>\n\n', 'tamborista_2004_old.htm', '0', '2026-05-07 23:42:44');
INSERT IGNORE INTO `pages` (`id`, `category_id`, `title`, `slug`, `content`, `original_file`, `sort_order`, `created_at`) VALUES ('129', '29', 'Fúltol en Moratalla. 2ª Cadete', 'fultol-en-moratalla-2a-cadete-8113', '\n\n<table border=\"1\" cellpadding=\"0\" cellspacing=\"0\"  border  id=\"AutoNumber5\">\n  <tr>\n    <td ><b><font size=\"4\" >\n    <embed   src=\"../../../images/atras.swf\" align=\"left\"></font></b></td>\n  </tr>\n</table>\n\n<p><font size=\"4\" ><b>ALEVÍN MASCULINO</b></font></p>\n\n<table border=\"1\" cellpadding=\"0\" cellspacing=\"0\"  id=\"AutoNumber1\"  >\n  <tr>\n    <td  ></td>\n  </tr>\n  <tr>\n    <td >\n    <b><font  size=\"2\" >Con la colaboración de \n    MIRIAM MARTÍNEZ RODRÍGUEZ</font></b></td>\n  </tr>\n  <tr>\n    <td >\n    <p >\n	<font  ><b><font size=\"2\">07/05/2005 - </font>\n	<span lang=\"ES-TRAD\"><font size=\"2\">JAIRIS ALCANTARILLA&nbsp;&nbsp; 69 NOROESTE \n	MORATALLA&nbsp; &nbsp;51</font></span></b></font></p>\n	<p class=\"MsoNormal\" >\n	<font  size=\"2\" >Disputado encuentro ante un \n	rival directo en la clasificación. Nuestros jugadores han vuelto a demostrar \n	la calidad que atesoran, han ido perdiendo durante el encuentro por unas \n	diferencias de 2-3 puntos. Hay que decir que han sufrido un deplorable \n	arbitraje que al final ha decantado el encuentro para el equipo local. A \n	pesar de la derrota hay que felicitarlos. ¡Enhorabuena!.</font></p>\n	<p class=\"MsoNormal\" >\n	<font  size=\"2\"><font >El próximo</font>\n	<font ><b><u>Sábado 14 de Mayo, a las 6 de la tarde</u></b>, \n	en el Pabellón Julio Cardozo</font>, <font >se disputa un \n	importantísimo partido contra San José de la Vega, vital para intentar \n	quedar entre los cuatro primeros, de cara a la disputa del título. Necesitan \n	ganar por más de 12 puntos, contra el 2º de la clasificación</font>.</font></p>\n	<p class=\"MsoNormal\" >\n	<font  size=\"2\" >Desde aquí animamos a que vaya \n	todo el mundo para animarlos y presionar al equipo rival, nuestros chicos \n	son capaces de eso y de más. Es muy importante que les apoyemos. Haced un \n	hueco en vuestros quehaceres y subid a animarlos.</font></td>\n  </tr>\n  <tr>\n    <td >\n    <p class=\"MsoNormal\" ><b>\n	<font  ><font size=\"2\">30/04/2005 -</font><span lang=\"ES-TRAD\"><font size=\"2\">NOROESTE \n	MORATALLA&nbsp; &nbsp;51&nbsp;&nbsp; FORTUNA&nbsp; 45</font></span></font></b></p>\n	<p class=\"MsoNormal\" >\n	<font  size=\"2\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; <font >Disputado \n	encuentro en el que nuestros jugadores han vuelto a demostrar la calidad que \n	atesoran, a pesar de realizar un mal juego. Está claro que todavía no lo han \n	dicho todo en este play-off. ¡Enhorabuena!.</font></font></td>\n  </tr>\n  <tr>\n    <td >\n    <p class=\"MsoNormal\" >\n	<font ><b><font size=\"2\" >23/04/2005 - </font>\n	<span lang=\"ES-TRAD\"><font ></font><font size=\"2\">\n	<font >POLARIS WORLD MURCIA&nbsp; &nbsp;&nbsp;&nbsp;NOROESTE MORATALLA&nbsp; </font>&nbsp;</font></span></b></font></p>\n	<p class=\"MsoNormal\" >\n	<font  size=\"2\" >Nuestros jugadores sufrieron \n	una abultada derrota, pero no por eso deben desanimarse. Hay que tener en \n	cuenta que este equipo no ha perdido ningún encuentro en toda la temporada. \n	No deben dejar de trabajar y seguir en la misma línea. ¡Ánimo!.</font></td>\n  </tr>\n  <tr>\n    <td >\n    <font  ><b><span lang=\"ES-TRAD\"><font size=\"2\">\n    09/04/2005 -</font></span></b></font><font  size=\"2\"><b><span lang=\"ES-TRAD\"> </span></b></font>\n    <font  size=\"2\" ><b><span lang=\"ES-TRAD\">C.B. \n	SIERRAMAR (de El Algar)&nbsp;&nbsp; 49&nbsp; NOROESTE MORATALLA&nbsp; &nbsp;58</span></b></font><p class=\"MsoNormal\" >\n    <font   size=\"2\">En palabras de su propio \n	entrenador, ha sido el partido más duro que han tenido que disputar hasta el \n	momento, por causa de otro pésimo arbitraje, y se les ha puesto muy cuesta \n	arriba desde el principio (sirva como ejemplo que a los 20 segundos ya \n	perdían 7-0), por ello esta victoria tiene más mérito todavía.</font><font  size=\"2\"><span > \n    Enhorabuena a nuestros “alevines de oro” y máxima concentración para el \n	próximo sábado contra CAB. Cartagena, rival empatado a puntos con los \n	nuestros</span></font></td>\n  </tr>\n  <tr>\n    <td >\n    <p ><b>\n    <font  size=\"2\" >12</font></b><font  ><b><span lang=\"ES-TRAD\"><font size=\"2\">/03/2005 \n    - </font></span></b></font><font  size=\"2\" ><b>\n    <span lang=\"ES-TRAD\">NOROESTE MORATALLA&nbsp; &nbsp;41 &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;JAIRIS ALCANTARILLA&nbsp; 36</span></b></font></p>\n    <p class=\"MsoNormal\" >\n    <font  size=\"2\" >Tercer partido de la Segunda \n    Fase. Este ha sido otro gran partido de nuestros alevines, disputado ante \n    uno de los mejores equipos de la competición, que quedó primero en el grupo \n    en el que jugó en la 1ª fase perdiendo un solo partido. Con este triunfo, \n    nuestros chicos dejan clara su candidatura al título y demuestran a los \n    demás equipos que son un rival a tener en cuenta. ¡Enhorabuena!.</font></p>\n    <p class=\"MsoNormal\" >\n    <font  size=\"2\" >Hay que felicitar también a \n    Jose, el entrenador de los alevines, que este fin de semana ha estado \n    también en su labor como entrenador ayudante de la Selección Alevín \n    Masculina de la Región de Murcia.</font></td>\n  </tr>\n  <tr>\n    <td >\n    <p align=\"left\" >\n    <font  ><b><font size=\"2\">05</font><span lang=\"ES-TRAD\"><font size=\"2\">/03/2005 \n    - </font></span></b></font><font  size=\"2\" ><b>\n    <span lang=\"ES-TRAD\">EDECO FORTUNA &nbsp;27&nbsp; NOROESTE MORATALLA&nbsp; &nbsp;&nbsp;43</span></b></font></p>\n    <p align=\"left\" >\n    <font size=\"2\"  >Segundo partido de la Segunda \n    Fase. El resultado no debe confundir porque, aunque el Fortuna posiblemente \n    sea inferior en calidad, en esta 2ª fase todos los partidos son muy \n    complicados y tiene mucho mérito cada una de las victorias que se consigan, \n    que estamos seguros de que van a ser muchas. ¡Enhorabuena!.</font></td>\n  </tr>\n  <tr>\n    <td >\n    <p align=\"left\" >\n    <font   size=\"2\"><b><span lang=\"ES-TRAD\">\n    26/02/2005 - NOROESTE MORATALLA&nbsp; &nbsp;&nbsp;C. B. MURCIA</span></b></font></p>\n    <p align=\"left\" >\n    <font  size=\"2\" >Primer partido de los Play-off. \n    Se perdió por una diferencia demasiado abultada, porque el otro equipo no \n    era tan superior como reflejó el marcador final. Nuestros chicos hicieron un \n    gran desgaste físico que, aunque no se vio reflejado en el marcador, si que \n    permitió ver su gran calidad. No deben desanimarse, y hay que tener en \n    cuenta que este equipo fue el campeón de esta categoría la temporada pasada.</font></td>\n  </tr>\n  <tr>\n    <td >\n    <p  align=\"left\"><font ><font  size=\"2\"><b>\n    12/02/2005</b></font><font ><b><span lang=\"ES-TRAD\" > </span>\n    <font size=\"2\"><span lang=\"ES-TRAD\">-  </span></font></b></font></font>\n    <font  size=\"2\" ><b><span lang=\"ES-TRAD\">\n    NOROESTE MORATALLA&nbsp; &nbsp;&nbsp;116&nbsp;&nbsp; BLANCA&nbsp;&nbsp; 14</span></b></font></p>\n    <p class=\"MsoNormal\" >\n    <font  size=\"2\" >Los calificativos se agotan \n    para describir a nuestros alevines. El resultado lo dice todo. Espectacular \n    partido de nuestros chicos que arrasaron totalmente al equipo de Blanca. Ya \n    en el partido de la 1ª vuelta les ganaron por 60 puntos de diferencia en su \n    propio campo. Estos chicos pueden hacer algo grande en los “play-off”. \n    ¡Enhorabuena! y ¡Ánimo!</font></td>\n  </tr>\n  <tr>\n    <td >\n    <p ><b>\n    <font  size=\"2\" >05</font></b><font ><font  size=\"2\"><b>/02/2005</b></font><font ><b><span lang=\"ES-TRAD\" > </span>\n    <font size=\"2\"><span lang=\"ES-TRAD\">-  </span></font></b></font><b>\n    <span lang=\"ES-TRAD\"><font size=\"2\" >C. B. MOLINA&nbsp;&nbsp; 24&nbsp;&nbsp;&nbsp;&nbsp; \n    NOROESTE MORATALLA&nbsp; 39</font></span></b></font></p>\n    <p ><font size=\"2\"  > Nueva \n    victoria de nuestros “alevines de oro” que les ha permitido clasificarse \n    matemáticamente para el play-off. El fin de semana que viene juegan el \n    último partido de temporada regular en el Pabellón “Julio Cardozo”, merece \n    la pena ir a verles jugar, para animarles, premiarles por esta gran \n    temporada que están haciendo y apoyarles para que empiecen el play-off con \n    fuerza y concentración.</font></td>\n  </tr>\n  <tr>\n    <td>\n    <p ><font >\n    <font  size=\"2\"><b>29/01/2005</b></font><font ><b><span lang=\"ES-TRAD\" > \n    - NO HUBO COMPETICIÓN.</span></b></font></font></td>\n  </tr>\n  <tr>\n    <td >\n    <p ><font >\n    <font  size=\"2\"><b>22/01/2005</b></font><font ><b><span lang=\"ES-TRAD\" > \n    - ARCHENA 28&nbsp;&nbsp; NOROESTE MORATALLA 45</span></b></font></font></p>\n    <p >\n    <font  >\n    <span lang=\"ES-TRAD\" >Cómoda victoria de nuestros \n    alevines. El resultado lo dice todo. Por suerte, nos tienen acostumbrados a \n    estos resultados. Enhorabuena.</span></font></td>\n  </tr>\n  <tr>\n    <td >\n    <p >\n    <font   size=\"2\"><b>15/01/2005 -\n    <span lang=\"ES-TRAD\">NOROESTE MORATALLA 46&nbsp;&nbsp;&nbsp; &nbsp;A. D. M. (de Molina) 48</span></b></font></p>\n    <p class=\"MsoNormal\" >\n    <font ><span lang=\"ES-TRAD\">&nbsp;Partido no apto para enfermos \n    del corazón, muy disputado y que se resolvió en los últimos segundos. \n    Faltando 15 segundos, Moratalla ganaba por 1 punto. Hicieron una falta para \n    cortar el contraataque, 2 tiros libres para Molina, de los cuales metieron \n    el primero (empate a 46) y fallaron el segundo, cogiendo el rebote y \n    anotando una canasta, no quedando tiempo para más.</span></font></p>\n    <p class=\"MsoNormal\" >\n    <font ><span lang=\"ES-TRAD\">&nbsp;De todas formas, nuestros \n    muchachos se dejaron la piel en el campo y lo dieron todo para conseguir la \n    victoria. Aunque no pudo ser, hay que felicitarlos por su entrega y buen \n    hacer.</span></font></td>\n  </tr>\n  <tr>\n    <td >\n    <p class=\"MsoNormal\" >\n    <font   size=\"2\"><b>08/01/2005- </b>\n    <span lang=\"ES-TRAD\">&nbsp; <b>JESUITINAS (de Murcia) 26 – NOROESTE MORATALLA 30</b></span></font></p>\n    <p class=\"MsoNormal\" >\n    <font ><span lang=\"ES-TRAD\">A pesar del bajo marcador, se \n    produjo una nueva exhibición de este equipo a las que ya nos tiene \n    acostumbrado, pero no por ello hay que restarle mérito.</span></font></p>\n    <p class=\"MsoNormal\" >\n    <font ><span lang=\"ES-TRAD\">&nbsp;Aunque hubo pocos puntos, \n    hicieron una gran hazaña, porque el otro equipo alineó ilegalmente a cuatro \n    jugadores de categoría infantil (una categoría superior, es decir, mayores \n    en edad que los nuestros) y aún así fueron capaces de imponerse en su propio \n    terreno.</span></font></td>\n  </tr>\n  <tr>\n    <td >\n    &nbsp;</td>\n  </tr>\n</table>\n\n<table CELLSPACING=\"3\" CELLPADDING=\"3\"  border=\"1\"  >\n  <tr>\n    <td  >\n    <div align=\"center\">\n      <center>\n      <table  border=\"1\" border cellspacing=\"1\" >\n        <tr >\n          <td align=\"middle\"  ><b>\n          <font  size=\"2\">Jornada</font></b></td>\n          <td align=\"middle\"  >\n          <font  size=\"2\"><b>Puntos</b></font></td>\n          <td align=\"middle\"  >\n          <font  size=\"2\"><b>Fecha</b></font></td>\n          <td align=\"middle\"  colSpan=\"3\" >\n          <p class=\"resultado2\"><font  size=\"2\"><b>Partido</b></font></td>\n        </tr>\n        <tr>\n          <td align=\"middle\"  ><b>\n          <font  size=\"2\">1</font></b></td>\n          <td align=\"middle\"  >\n          </td>\n          <td align=\"middle\"  ></td>\n          <td onmouseover=\"this.style.backgroundColor=\'yellow\'\" onmouseout=\"this.style.backgroundColor=\'\'\" align=\"right\"  >\n          </td>\n          <td align=\"middle\"  >\n          </td>\n 