INSERT IGNORE INTO `pages` (`id`, `category_id`, `title`, `slug`, `content`, `original_file`, `sort_order`, `created_at`) VALUES ('131', '29', 'Fúltol en Moratalla. 2ª Cadete', 'fultol-en-moratalla-2a-cadete-6964', '\n\n<table border=\"1\" cellpadding=\"0\" cellspacing=\"0\"  border  id=\"AutoNumber5\">\n  <tr>\n    <td ><b><font size=\"4\" >\n    <embed   src=\"../../../images/atras.swf\" align=\"left\"></font></b></td>\n  </tr>\n</table>\n\n<p><font size=\"4\" ><b>BEJAMÍN MASCULINO</b></font></p>\n\n<table border=\"1\" cellpadding=\"0\" cellspacing=\"0\"  id=\"AutoNumber1\"  >\n  <tr>\n    <td  ></td>\n  </tr>\n  <tr>\n    <td >\n    <b><font  size=\"2\" >Con la colaboración de \n    MIRIAM MARTÍNEZ RODRÍGUEZ</font></b></td>\n  </tr>\n  <tr>\n    <td>\n    <p ><font  ><b><span lang=\"ES-TRAD\"><font size=\"2\">\n    09/04/2005 \n    -</font></span></b></font><font  size=\"2\"><b><span lang=\"ES-TRAD\"> </span></b></font>\n    <b><span lang=\"ES-TRAD\" >\n    <font size=\"2\" >JESUITINAS (de Murcia)&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; NOROESTE \n    MORATALLA&nbsp; </font></span>\n    <span lang=\"ES-TRAD\" >\n    &nbsp;</span></b></p>\n    <p class=\"MsoNormal\" >\n    <font  size=\"2\" >Han perdido nuestros \n    benjamines, pero no deben desanimarse porque están jugando mejor, por eso \n    tienen que seguir trabajando y esforzándose en los entrenamientos porque lo \n    están haciendo muy bien.</font></td>\n  </tr>\n  <tr>\n    <td>\n    <p ><b>\n    <font  size=\"2\" >12</font></b><font  ><b><span lang=\"ES-TRAD\"><font size=\"2\">/03/2005 \n    -</font></span></b></font><font  size=\"2\"><b><span lang=\"ES-TRAD\">\n    <font >NOROESTE MORATALLA&nbsp; &nbsp;6&nbsp;&nbsp; INFANTE&nbsp; 16</font></span></b></font></p>\n    <p >\n    <font  size=\"2\" >Han perdido contra un equipo \n    con gran tradición baloncestística. No deben desanimarse por perder algún \n    partido. Están empezando pero apuntan muy buenas maneras. Hay que seguir \n    trabajando. ¡Ánimo!.</font></td>\n  </tr>\n  <tr>\n    <td>\n    <p align=\"left\" >\n    <font  ><b><font size=\"2\">05</font><span lang=\"ES-TRAD\"><font size=\"2\">/03/2005 \n    - </font></span></b></font><font  size=\"2\" ><b>\n    <span lang=\"ES-TRAD\">C.B. SANTOMERA&nbsp;&nbsp; NOROESTE MORATALLA&nbsp;</span></b></font></p>\n    <p align=\"left\" >\n    <font  size=\"2\" >Perdieron este partido, pero \n    no deben desanimarse, porque están empezando a competir. ¡Ánimo!.</font></td>\n  </tr>\n  <tr>\n    <td>\n    <p align=\"left\" >\n    <font   size=\"2\"><b><span lang=\"ES-TRAD\">\n    26/02/2005 - NOROESTE MORATALLA&nbsp; 24&nbsp; C. B. MURCIA&nbsp; 15</span></b></font></p>\n    <p align=\"left\" >\n    <span ><font size=\"2\" >Nuestros \n    benjamines han logrado una trabajada victoria ante un gran rival. Se \n    esforzaron al máximo y dieron todo lo que tenían. Deben seguir así y \n    conseguirán más victorias.</font></span></td>\n  </tr>\n  <tr>\n    <td>\n    <p ><font ><font  size=\"2\"><b>\n    12/02/2005</b></font><font ><b><span lang=\"ES-TRAD\" > \n    - DESCANSO</span></b></font></font></td>\n  </tr>\n  <tr>\n    <td >\n    <p class=\"MsoNormal\" >\n    <b><font  size=\"2\" >05</font></b><font ><font  size=\"2\"><b>/02/2005</b></font><font ><b><span lang=\"ES-TRAD\" > \n    -  </span></b></font></font><font  size=\"2\" ><b>\n    JAIRIS ALCANTARILLA&nbsp;&nbsp;&nbsp; NOROESTE MORATALLA</b></font></p>\n    <p class=\"MsoNormal\" >\n    <font  size=\"2\" ><span lang=\"ES-TRAD\">Este ha \n    sido el debut en la competición oficial. Se ha empezado con una derrota pero \n    no tienen que desanimarse. La próxima vez seguro que ganan.</span></font></td>\n  </tr>\n  <tr>\n    <td>\n    <font >\n    <font  size=\"2\"><b>29/01/2005</b></font><font ><b><span lang=\"ES-TRAD\" > \n    - NO HUBO COMPETICIÓN.</span></b></font></font></td>\n  </tr>\n  <tr>\n    <td >\n    <p ><font >\n    <font  size=\"2\"><b>22/01/2005</b></font><font ><b><span lang=\"ES-TRAD\" > \n    - CALASPARRA 2&nbsp;&nbsp; NOROESTE MORATALLA 25</span></b></font></font></p>\n    <p class=\"MsoNormal\" >\n    <font  >\n    <span lang=\"ES-TRAD\" >Excelente victoria de este \n    equipo debutante, a los que hay que animar, pues son la categoría más \n    pequeña del club.&nbsp;</span></font></td>\n  </tr>\n  <tr>\n    <td >\n    &nbsp;</td>\n  </tr>\n</table>\n\n<table CELLSPACING=\"3\" CELLPADDING=\"3\"  border=\"1\"  >\n  <tr>\n    <td  >\n    <div align=\"center\">\n      <center>\n      <table  border=\"1\" border cellspacing=\"1\" >\n        <tr >\n          <td align=\"middle\"  ><b>\n          <font  size=\"2\">Jornada</font></b></td>\n          <td align=\"middle\"  >\n          <font  size=\"2\"><b>Puntos</b></font></td>\n          <td align=\"middle\"  >\n          <font  size=\"2\"><b>Fecha</b></font></td>\n          <td align=\"middle\"  colSpan=\"3\" >\n          <p class=\"resultado2\"><font  size=\"2\"><b>Partido</b></font></td>\n        </tr>\n        <tr>\n          <td align=\"middle\"  ><b>\n          <font  size=\"2\">1</font></b></td>\n          <td align=\"middle\"  >\n          </td>\n          <td align=\"middle\"  ></td>\n          <td onmouseover=\"this.style.backgroundColor=\'yellow\'\" onmouseout=\"this.style.backgroundColor=\'\'\" align=\"right\"  >\n          </td>\n          <td align=\"middle\"  >\n          </td>\n          <td onmouseover=\"this.style.backgroundColor=\'yellow\'\" onmouseout=\"this.style.backgroundColor=\'\'\" align=\"left\"  >\n          </td>\n        </tr>\n        <tr>\n          <td align=\"middle\"  ><b>\n          <font  size=\"2\">2</font></b></td>\n          <td align=\"middle\"  >\n          &nbsp;</td>\n          <td align=\"middle\"  >&nbsp;</td>\n          <td onmouseover=\"this.style.backgroundColor=\'yellow\'\" onmouseout=\"this.style.backgroundColor=\'\'\" align=\"right\"  >\n          &nbsp;</td>\n          <td align=\"middle\"  >\n          &nbsp;</td>\n          <td onmouseover=\"this.style.b