INSERT IGNORE INTO `pages` (`id`, `category_id`, `title`, `slug`, `content`, `original_file`, `sort_order`, `created_at`) VALUES ('135', '30', 'Fúltol en Moratalla. 2ª Cadete', 'fultol-en-moratalla-2a-cadete-2200', '\n\n<table border=\"1\" cellpadding=\"0\" cellspacing=\"0\"  border  id=\"AutoNumber5\">\n  <tr>\n    <td ><b><font size=\"4\" >\n    <embed   src=\"../../../images/atras.swf\" align=\"left\"></font></b></td>\n  </tr>\n</table>\n\n<p><b><font size=\"4\" >2ª AUTONÓMICA</font></b></p>\n\n<table border=\"1\" cellpadding=\"0\" cellspacing=\"0\"  id=\"AutoNumber1\"  >\n  <tr>\n    <td  ></td>\n  </tr>\n  <tr>\n    <td >\n    <b><font  size=\"2\" >Con la colaboración de \n    MIRIAM MARTÍNEZ RODRÍGUEZ</font></b></td>\n  </tr>\n  <tr>\n    <td >\n    &nbsp;</td>\n  </tr>\n  <tr>\n    <td >\n    <p class=\"MsoNormal\" >\n	<font  size=\"2\"><b><font ><span lang=\"es\">\n	19/11/2005 - </span></font><span lang=\"ES-TRAD\"><font >\n	NOROESTE </font><span >MORATALLA</span><font > \n	78 - Promociones y Construcciones JUANDE (Murcia) 69</font></span></b></font></p>\n	<p class=\"MsoNormal\" >\n	<font  size=\"2\" ><span lang=\"ES-TRAD\">Partido \n	muy disputado, sin grandes diferencias, en el que, tras ir ganando casi todo \n	el encuentro, a falta de 5 minutos se produjo un empate.&nbsp; En ese momento, \n	los nuestros supieron reaccionar y se impusieron con autoridad.</span></font></p>\n	<p class=\"MsoNormal\" >\n	<font  size=\"2\" ><span lang=\"ES-TRAD\">Decir que \n	el próximo partido será el Sábado 4 de Diciembre, a las 6 y media de la \n	tarde, CONTRA CARAVACA, que no falte nadie para machacar a nuestro eterno \n	rival.</span></font></td>\n  </tr>\n  <tr>\n    <td >\n    &nbsp;</td>\n  </tr>\n  </table>\n\n<span >\n<font  size=\"1\">Moratalla, \nMurcia, Turismo, Trieta, Espana, España,cultura, casas rurales, rural, alojamientos, Pablo \nSalinas Marin,alharabe, benamor, casa cristo, encantada, san jorge, buitre, sabinar, otos, cañada de la cruz, benizar, mazuza, calar de la santa, campo san juan, campo bejar, rogativa, zaen, murtas, nogueras, bajil,\nrupestres, rupestre,pinturas, pintura,mediterraneo,banda, rondalla,naturaleza, montaña, campo, monte, \npueblo, castillo, iglesia, calles, fiestas, musica, Maria del Carmen Rodriguez Rodriguez, \nPablo Salinas Rodriguez, Francisco Salinas Rodriguez\n</font></span></span></p>\n\n', 'autonomica2.htm', '0', '2026-05-07 23:42:44');
