INSERT IGNORE INTO `pages` (`id`, `category_id`, `title`, `slug`, `content`, `original_file`, `sort_order`, `created_at`) VALUES ('137', '30', 'Fúltol en Moratalla. 2ª Cadete', 'fultol-en-moratalla-2a-cadete-6601', '\n\n<table border=\"1\" cellpadding=\"0\" cellspacing=\"0\"  border  id=\"AutoNumber5\">\n  <tr>\n    <td ><b><font size=\"4\" >\n    <embed   src=\"../../../images/atras.swf\" align=\"left\"></font></b></td>\n  </tr>\n</table>\n\n<p><b><font size=\"4\" >CADETE FEMENINO<a href=\"../2005/images/cadete-femeninow.JPG\" target=\"_blank\"><img border=\"0\" src=\"../2005/images/cadete-femeninop.jpg\"  ></a></font></b></p>\n\n<table border=\"1\" cellpadding=\"0\" cellspacing=\"0\"  id=\"AutoNumber1\"  >\n  <tr>\n    <td  ></td>\n  </tr>\n  <tr>\n    <td >\n    <p >\n    <b><font  size=\"2\" >Con la colaboración de \n    MIRIAM MARTÍNEZ RODRÍGUEZ</font></b></p>\n    <p >\n    <font  size=\"1\" >No se visualizan los \n    resultados, por ser no ser relevantes, el equipo está actualmente en fase de \n    desarrollo, por lo que desde esta página se les anima a continuar con ese \n    espíritu de sacrificio.</font></td>\n  </tr>\n  <tr>\n    <td >\n    &nbsp;</td>\n  </tr>\n  <tr>\n    <td >\n    <p class=\"MsoNormal\" >\n	<font  size=\"2\"><b><font ><span lang=\"es\">\n	27/11/2005 </span></font><span lang=\"ES-TRAD\"><font >\n	CARTAGENA – NOROESTE </font><span >MORATALLA</span></span></b></font></p>\n	<p class=\"MsoNormal\" >\n	<font  size=\"2\" ><span lang=\"ES-TRAD\">No \n	disponemos del resultado exacto, solamente hay que decir que ha sido una \n	derrota de nuestras jugadoras por una diferencia sustancial.</span></font></p>\n	<p class=\"MsoNormal\" >\n	<font  size=\"2\" ><span lang=\"ES-TRAD\">No \n	sabemos qué les ocurre, pero están encestando menos de lo habitual y su \n	defensa ha bajado en intensidad. Deben centrarse y pensar que la línea que \n	llevaban anteriormente era la correcta. El trabajo en los entrenamientos se \n	está haciendo bien, pero se pierde la concentración en los partidos.</span></font></p>\n	<p class=\"MsoNormal\" >\n	<font  size=\"2\" ><span lang=\"ES-TRAD\">Hay que \n	decirles que no se tienen que desanimar, que vuelvan a poner toda la carne \n	en el asador y los resultados serán mejores. ¡ÁNIMO!.</span></font></td>\n  </tr>\n  <tr>\n    <td >\n    <p class=\"MsoNormal\" >\n	<font ><b><font  size=\"2\"><span lang=\"es\">\n	19/11/2005 </span></font><span lang=\"ES-TRAD\"><font >\n	<font size=\"2\">JESUITINAS (de Murcia) – NOROESTE </font></font>\n	<span ><font size=\"2\">MORATALLA</font></span></span></b></font></p>\n	<p class=\"MsoNormal\" >\n	<font  size=\"2\" ><span lang=\"ES-TRAD\">No \n	disponemos del resultado exacto, solamente que decir que ha sido una derrota \n	de nuestras jugadoras por una diferencia sustancial.&nbsp;</span></font></p>\n	<p class=\"MsoNormal\" >\n	<font  size=\"2\" ><span lang=\"ES-TRAD\">Nuestras \n	chicas entran ahora en una fase de la competición que podríamos decir que \n	“no es la suya”. Van a tener ahora una serie de partidos contra unas rivales \n	que llevan muchos más años que ellas entrenando, y eso se nota en la pista.</span></font></p>\n	<p class=\"MsoNormal\" >\n	<font  size=\"2\" ><span lang=\"ES-TRAD\">Ante \n	Jesuitas, además de lo dicho anteriormente, se han enfrentado a un arbitraje \n	injusto en el que ha habido gran permisividad a la defensa de las de Murcia, \n	lo que ha hecho perder la concentración a nuestras chicas.</span></font></p>\n	<p class=\"MsoNormal\" >\n	<font  size=\"2\" ><span lang=\"es\">H</span><span lang=\"ES-TRAD\">ay \n	que decirles que no se tienen que desanimar, que deben seguir entrenando \n	como hasta ahora y mejorar el control del balón. ¡ÁNIMO!.</span></font></td>\n  </tr>\n  <tr>\n    <td >\n    &nbsp;</td>\n  </tr>\n  <tr>\n    <td >\n    &nbsp;</td>\n  </tr>\n  <tr>\n    <td >\n    &nbsp;</td>\n  </tr>\n  <tr>\n    <td >\n    &nbsp;</td>\n  </tr>\n  <tr>\n    <td >\n    &nbsp;</td>\n  </tr>\n  <tr>\n    <td >\n    &nbsp;</td>\n  </tr>\n  <tr>\n    <td >\n    &nbsp;</td>\n  </tr>\n  <tr>\n    <td >\n    &nbsp;</td>\n  </tr>\n</table>\n\n<span >\n<font  size=\"1\">Moratalla, \nMurcia, Turismo, Trieta, Espana, España,cultura, casas rurales, rural, alojamientos, Pablo \nSalinas Marin,alharabe, benamor, casa cristo, encantada, san jorge, buitre, sabinar, otos, cañada de la cruz, benizar, mazuza, calar de la santa, campo san juan, campo bejar, rogativa, zaen, murtas, nogueras, bajil,\nrupestres, rupestre,pinturas, pintura,mediterraneo,banda, rondalla,naturaleza, montaña, campo, monte, \npueblo, castillo, iglesia, calles, fiestas, musica, Maria del Carmen Rodriguez Rodriguez, \nPablo Salinas Rodriguez, Francisco Salinas Rodriguez\n</font></span></span></p>\n\n', 'cadetefemenino.htm', '0', '2026-05-07 23:42:44');
