INSERT IGNORE INTO `pages` (`id`, `category_id`, `title`, `slug`, `content`, `original_file`, `sort_order`, `created_at`) VALUES ('139', '30', 'Fúltol en Moratalla. 2ª Cadete', 'fultol-en-moratalla-2a-cadete-1374', '\n\n<table border=\"1\" cellpadding=\"0\" cellspacing=\"0\"  border  id=\"AutoNumber5\">\n  <tr>\n    <td ><b><font size=\"4\" >\n    <embed   src=\"../../../images/atras.swf\" align=\"left\"></font></b></td>\n  </tr>\n</table>\n\n<p><b><font size=\"4\" >INFANTIL MASCULINO</font></b></p>\n\n<table border=\"1\" cellpadding=\"0\" cellspacing=\"0\"  id=\"AutoNumber1\"  >\n  <tr>\n    <td  ></td>\n  </tr>\n  <tr>\n    <td >\n    <b><font  size=\"2\" >Con la colaboración de \n    MIRIAM MARTÍNEZ RODRÍGUEZ</font></b></td>\n  </tr>\n  <tr>\n    <td >\n    <p >&nbsp;</td>\n  </tr>\n  <tr>\n    <td >\n    <p class=\"MsoNormal\" >\n	<font  size=\"2\"><b><font ><span lang=\"es\">\n	27/11/2005 - </span><span lang=\"ES-TRAD\">NOROESTE </span></font>\n	<span lang=\"ES-TRAD\"><span >MORATALLA&nbsp; </span>\n	<font >2 – C.B. BEGASTRI (de Cehegín)&nbsp; 0</font></span></b></font></p>\n	<p class=\"MsoNormal\" >\n	<font  size=\"2\"><span lang=\"ES-TRAD\"><font >\n	Este curioso resultado se dio porque el Begastri se presentó con 7 \n	jugadores, cuando el reglamento de esta competición obliga a presentar un \n	mínimo de 8, por lo que los árbitros les dieron el partido por perdido por \n	la diferencia mínima.</font></span></font></p>\n	<p class=\"MsoNormal\" >\n	<font  size=\"2\" ><span lang=\"ES-TRAD\">De todas \n	formas jugaron una “pachanguita” y nuestros chicos ganaron, como era de \n	esperar.</span></font></td>\n  </tr>\n  <tr>\n    <td >\n    <p class=\"MsoNormal\" >\n	<font ><b><font ><span lang=\"es\">\n	<font size=\"2\">19/11/2005 </font></span></font><span lang=\"ES-TRAD\">\n	<font ></font><font size=\"2\"><font >CEHEGÍN 35 \n	– NOROESTE </font><span >MORATALLA </span>\n	<font >26</font></font></span></b></font></p>\n	<p class=\"MsoNormal\" >\n	<font  size=\"2\"><span lang=\"ES-TRAD\"><font >El \n	equipo infantil jugó un poco adormecido, como se suele decir “no se bajaron \n	del autobús”.&nbsp; A estos si que hay que darles un pequeño tirón de orejas \n	porque lo pueden hacer mucho mejor, y ellos lo saben. Hay que decirles que \n	no deben sentirse mejores que los rivales y tienen que plantearse todos lo \n	partidos por igual e intentar ganarlos con las mismas ganas.</font></span></font></p>\n	<p class=\"MsoNormal\" >\n	<font  size=\"2\" ><span lang=\"ES-TRAD\">Esto solo \n	ha sido un tropezón, seguro que el próximo lo ganáis.</span></font></td>\n  </tr>\n  <tr>\n    <td >\n    &nbsp;</td>\n  </tr>\n  <tr>\n    <td >\n    &nbsp;</td>\n  </tr>\n  <tr>\n    <td >\n    &nbsp;</td>\n  </tr>\n  <tr>\n    <td >\n    &nbsp;</td>\n  </tr>\n  <tr>\n    <td >\n    &nbsp;</td>\n  </tr>\n  <tr>\n    <td >\n    &nbsp;</td>\n  </tr>\n  <tr>\n    <td >\n    &nbsp;</td>\n  </tr>\n  <tr>\n    <td >\n    &nbsp;</td>\n  </tr>\n  <tr>\n    <td >\n    &nbsp;</td>\n  </tr>\n  <tr>\n    <td >\n    &nbsp;</td>\n  </tr>\n  <tr>\n    <td >\n    &nbsp;</td>\n  </tr>\n  <tr>\n    <td >\n    &nbsp;</td>\n  </tr>\n</table>\n\n<span >\n<font  size=\"1\">Moratalla, \nMurcia, Turismo, Trieta, Espana, España,cultura, casas rurales, rural, alojamientos, Pablo \nSalinas Marin,alharabe, benamor, casa cristo, encantada, san jorge, buitre, sabinar, otos, cañada de la cruz, benizar, mazuza, calar de la santa, campo san juan, campo bejar, rogativa, zaen, murtas, nogueras, bajil,\nrupestres, rupestre,pinturas, pintura,mediterraneo,banda, rondalla,naturaleza, montaña, campo, monte, \npueblo, castillo, iglesia, calles, fiestas, musica, Maria del Carmen Rodriguez Rodriguez, \nPablo Salinas Rodriguez, Francisco Salinas Rodriguez\n</font></span></span></p>\n\n', 'infantilmasculino.htm', '0', '2026-05-07 23:42:44');
INSERT IGNORE INTO `pages` (`id`, `category_id`, `title`, `slug`, `content`, `original_file`, `sort_order`, `created_at`) VALUES ('140', '30', 'Fúltol en Moratalla. 2ª Cadete', 'fultol-en-moratalla-2a-cadete-2408', '\n\n<table border=\"1\" cellpadding=\"0\" cellspacing=\"0\"  border  id=\"AutoNumber5\">\n  <tr>\n    <td ><b><font size=\"4\" >\n    <embed   src=\"../../../images/atras.swf\" align=\"left\"></font></b></td>\n  </tr>\n</table>\n\n<p><b><font size=\"4\" >MINIBASKET</font></b></p>\n\n<table border=\"1\" cellpadding=\"0\" cellspacing=\"0\"  id=\"AutoNumber1\"  >\n  <tr>\n    <td  ></td>\n  </tr>\n  <tr>\n    <td >\n    <b><font  size=\"2\" >Con la colaboración de \n    MIRIAM MARTÍNEZ RODRÍGUEZ</font></b></td>\n  </tr>\n  <tr>\n    <td >\n    <p >&nbsp;</td>\n  </tr>\n  <tr>\n    <td >\n    <p class=\"MsoNormal\" >\n	<font  size=\"2\"><b><font ><span lang=\"es\">\n	19/11/2005 - </span><span lang=\"ES-TRAD\">NOROESTE </span></font>\n	<span lang=\"ES-TRAD\"><span >MORATALLA</span><font > \n	– CEHEGÍN</font></span></b></font></p>\n	<p class=\"MsoNormal\" >\n	<font  size=\"2\" ><span lang=\"ES-TRAD\">Debut del \n	equipo de minibasket con derrota.</span></font></p>\n	<p class=\"MsoNormal\" >\n	<font  size=\"2\" ><span lang=\"ES-TRAD\">No deben \n	darle más importancia de la que tiene. Es su debut en la competición y no es \n	más que un compartido. Lo&nbsp; han hecho muy bien, pero les faltó un poquito más \n	de tranquilidad. La próxima vez seguro que saldrá mejor.</span></font></td>\n  </tr>\n  <tr>\n    <td >\n    &nbsp;</td>\n  </tr>\n  <tr>\n    <td >\n    &nbsp;</td>\n  </tr>\n  <tr>\n    <td >\n    &nbsp;</td>\n  </tr>\n  <tr>\n    <td >\n    &nbsp;</td>\n  </tr>\n  <tr>\n    <td >\n    &nbsp;</td>\n  </tr>\n  <tr>\n    <td >\n    &nbsp;</td>\n  </tr>\n  <tr>\n    <td >\n    &nbsp;</td>\n  </tr>\n  <tr>\n    <td >\n    &nbsp;</td>\n  </tr>\n  <tr>\n    <td >\n    &nbsp;</td>\n  </tr>\n  <tr>\n    <td >\n    &nbsp;</td>\n  </tr>\n  <tr>\n    <td >\n    &nbsp;</td>\n  </tr>\n  <tr>\n    <td >\n    &nbsp;</td>\n  </tr>\n</table>\n\n<span >\n<font  size=\"1\">Moratalla, \nMurcia, Turismo, Trieta, Espana, España,cultura, casas rurales, rural, alojamientos, Pablo \nSalinas Marin,alharabe, benamor, casa cristo, encantada, san jorge, buitre, sabinar, otos, cañada de la cruz, benizar, mazuza, calar de la santa, campo san juan, campo bejar, rogativa, zaen, murtas, nogueras, bajil,\nrupestres, rupestre,pinturas, pintura,mediterraneo,banda, rondalla,naturaleza, montaña, campo, monte, \npueblo, castillo, iglesia, calles, fiestas, musica, Maria del Carmen Rodriguez Rodriguez, \nPablo Salinas Rodriguez, Francisco Salinas Rodriguez\n</font></span></span></p>\n\n', 'minibasket.htm', '0', '2026-05-07 23:42:44');
