INSERT IGNORE INTO `pages` (`id`, `category_id`, `title`, `slug`, `content`, `original_file`, `sort_order`, `created_at`) VALUES ('164', '40', 'Pagina nueva 1', 'pagina-nueva-1-1268', '\n\n<table border=\"0\" cellspacing=\"1\"  id=\"AutoNumber1\" >\n  <tr>\n    <td  colspan=\"5\" >\n    <p align=\"center\"><b><font  size=\"4\">Fotografías de San Antón (Enero \n    2004)</font></b></td>\n  </tr>\n  <tr>\n    <td  >\n    <a href=\"Images/San-Anton-16.jpg\" target=\"_blank\">\n    <img border=\"0\" src=\"Images/San-Anton-16p.jpg\"  ></a><a href=\"Images/San-Anton-04.jpg\" target=\"_blank\"><img border=\"0\" src=\"Images/San-Anton-04p.jpg\"  ></a></td>\n    <td  ><a href=\"Images/San-Anton-13.jpg\">\n    <img border=\"0\" src=\"Images/San-Anton-13p.jpg\"  ></a></td>\n    <td  >&nbsp;</td>\n    <td  >&nbsp;</td>\n    <td  >&nbsp;</td>\n  </tr>\n  <tr>\n    <td  >\n    <a href=\"Images/San-Anton-07.jpg\" target=\"_blank\">\n    <img border=\"0\" src=\"Images/San-Anton-07p.jpg\"  ></a><a href=\"Images/San-Anton-10.jpg\" target=\"_blank\"><img border=\"0\" src=\"Images/San-Anton-10p.jpg\"  ></a></td>\n    <td  >\n    <a href=\"Images/San-Anton-08.jpg\" target=\"_blank\">\n    <img border=\"0\" src=\"Images/San-Anton-08p.jpg\"  ></a></td>\n    <td  >&nbsp;</td>\n    <td  >&nbsp;</td>\n    <td  >&nbsp;</td>\n  </tr>\n  <tr>\n    <td  >\n    <a href=\"Images/San-Anton-09.jpg\" target=\"_blank\">\n    <img border=\"0\" src=\"Images/San-Anton-09p.jpg\"  ></a><a href=\"Images/San-Anton-03.jpg\" target=\"_blank\"><img border=\"0\" src=\"Images/San-Anton-03p.jpg\"  ></a></td>\n    <td  >\n    <a href=\"Images/San-Anton-14.jpg\" target=\"_blank\">\n    <img border=\"0\" src=\"Images/San-Anton-14p.jpg\"  ></a></td>\n    <td  >&nbsp;</td>\n    <td  >&nbsp;</td>\n    <td  >&nbsp;</td>\n  </tr>\n  <tr>\n    <td  >\n    <a href=\"Images/San-Anton-11.jpg\" target=\"_blank\">\n    <img border=\"0\" src=\"Images/San-Anton-11p.jpg\"  ></a><a href=\"Images/San-Anton-12.jpg\" target=\"_blank\"><img border=\"0\" src=\"Images/San-Anton-12p.jpg\"  ></a></td>\n    <td  >\n    <a href=\"Images/San-Anton-05.jpg\" target=\"_blank\">\n    <img border=\"0\" src=\"Images/San-Anton-05p.jpg\"  ></a></td>\n    <td  >&nbsp;</td>\n    <td  >&nbsp;</td>\n    <td  >&nbsp;</td>\n  </tr>\n  <tr>\n    <td  ><a href=\"Images/San-Anton-06p.jpg\">\n    <img border=\"0\" src=\"Images/San-Anton-06p.jpg\"  ></a><a href=\"Images/San-Anton-02p.jpg\" target=\"_blank\"><img border=\"0\" src=\"Images/San-Anton-02p.jpg\"  ></a></td>\n    <td  >\n    <a href=\"Images/San-Anton-01.jpg\" target=\"_blank\">\n    <img border=\"0\" src=\"Images/San-Anton-01p.jpg\"  ></a></td>\n    <td  >&nbsp;</td>\n    <td  >&nbsp;</td>\n    <td  >&nbsp;</td>\n  </tr>\n</table>\n\n', 'sananton.htm', '0', '2026-05-07 23:42:45');
INSERT IGNORE INTO `pages` (`id`, `category_id`, `title`, `slug`, `content`, `original_file`, `sort_order`, `created_at`) VALUES ('165', '43', 'SSTA', 'ssta-9804', '\n\n<p align=\"center\"><b><font size=\"5\"  >SEMANA SANTA</font></b></p>\n\n<p align=\"left\"><font ><big><font  size=\"2\">&nbsp;&nbsp;&nbsp;&nbsp; \nMoratalla tiene como tradición ancestral, además de las procesiones típicas de \nestas fechas, de tocar el \ntambor, el toque moratallero es exclusivo, no se repite en ningún otro lugar de la \npenínsula, esto se puede constatar en las concentraciones que anualmente se celebran, \ncon motivo de las Jornadas Nacionales para la \nExaltación del Tambor y el Bombo en distintos pueblos y ciudades de nuestra geografía nacional.</font></big></font><font   size=\"2\">&nbsp;&nbsp;&nbsp;&nbsp; </font>\n</p>\n\n<p align=\"left\"><font   size=\"2\">Los días de Jueves Santo, Viernes Santo y \nDomingo de Resurrección, Moratalla se convierte en un estruendo. Cada tamborista, que es \nel nombre que recibe el nazareno que toca el tambor, intentará demostrar su \ndestreza, refinamiento y fuerza, así como, la limpieza de sonido de \nsu tambor. El estruendo generado se debe a que cada tamborista hace su toque y no va acompasado con ningún otro, \naunque individualmente el toque es totalmente rítmico. Hay quien dice que esto fue \nlo que se oiría cuando Jesucristo fue crucificado.</font></p>\n\n<p align=\"center\">\n<embed   src=\"../../Asociaciones/Tamboristas/2004/Images/Semana_Santa_2004.swf\"></p>\n\n<p align=\"center\">\n<b><font >\n    <a href=\"Images/tambor3.wav\" >\n<font   size=\"2\">Toque de Tambor Moratallero (6 \n    Seg)</font></a></font></b><a target=\"_self\" href=\"Images/tambor3.wav\"><font   size=\"2\"><img src=\"Images/tamborbo.gif\" alt=\"BEBE1.GIF (10639 bytes)\" border=\"0\"  ></font></a></p>\n\n<p align=\"center\">\n&nbsp;</p>\n\n<p align=\"left\"><font ><big>&nbsp;&nbsp;&nbsp; </big></font></p>\n', 'ssta.htm', '0', '2026-05-07 23:42:45');
INSERT IGNORE INTO `pages` (`id`, `category_id`, `title`, `slug`, `content`, `original_file`, `sort_order`, `created_at`) VALUES ('167', '44', 'SSTA', 'ssta-1024', '\n\n<p align=\"center\"><b><font size=\"5\"  >SEMANA SANTA</font></b></p>\n\n<p align=\"left\"><font ><big><font  size=\"2\">&nbsp;&nbsp;&nbsp;&nbsp; \nMoratalla tiene como tradición ancestral, además de las procesiones típicas de \nestas fechas, de tocar el \ntambor, el toque moratallero es exclusivo, no se repite en ningún otro lugar de la \npenínsula, esto se puede constatar en las concentraciones que anualmente se celebran, \ncon motivo de las Jornadas Nacionales para la \nExaltación del Tambor y el Bombo en distintos pueblos y ciudades de nuestra geografía nacional.</font></big></font><font   size=\"2\">&nbsp;&nbsp;&nbsp;&nbsp; </font>\n</p>\n\n<p align=\"left\"><font   size=\"2\">Los días de Jueves Santo, Viernes Santo y \nDomingo de Resurrección, Moratalla se convierte en un estruendo. Cada tamborista, que es \nel nombre que recibe el nazareno que toca el tambor, intentará demostrar su \ndestreza, refinamiento y fuerza, así como, la limpieza de sonido de \nsu tambor. El estruendo generado se debe a que cada tamborista hace su toque y no va acompasado con ningún otro, \naunque individualmente el toque es totalmente rítmico. Hay quien dice que esto fue \nlo que se oiría cuando Jesucristo fue crucificado.</font></p>\n\n<p align=\"center\">\n<embed   src=\"../../Asociaciones/Tamboristas/2004/Images/Semana_Santa_2004.swf\"></p>\n\n<p align=\"center\">\n<b><font >\n    <a href=\"Images/tambor3.wav\" >\n<font   size=\"2\">Toque de Tambor Moratallero (6 \n    Seg)</font></a></font></b><a target=\"_self\" href=\"Images/tambor3.wav\"><font   size=\"2\"><img src=\"Images/tamborbo.gif\" alt=\"BEBE1.GIF (10639 bytes)\" border=\"0\"  ></font></a></p>\n\n<p align=\"center\">\n&nbsp;</p>\n\n<p align=\"left\"><font ><big>&nbsp;&nbsp;&nbsp; </big></font></p>\n', 'ssta.htm', '0', '2026-05-07 23:42:45');
INSERT IGNORE INTO `pages` (`id`, `category_id`, `title`, `slug`, `content`, `original_file`, `sort_order`, `created_at`) VALUES ('168', '44', 'SSTA', 'ssta-7716', '\n\n<p align=\"center\"><b><font size=\"5\"  >SEMANA SANTA</font></b></p>\n\n<p align=\"left\"><font ><big><font  size=\"2\">&nbsp;&nbsp;&nbsp;&nbsp; \nMoratalla tiene como tradición ancestral, además de las procesiones típicas de \nestas fechas, de tocar el \ntambor, el toque moratallero es exclusivo, no se repite en ningún otro lugar de la \npenínsula, esto se puede constatar en las concentraciones que anualmente se celebran, \ncon motivo de las Jornadas Nacionales para la \nExaltación del Tambor y el Bombo en distintos pueblos y ciudades de nuestra geografía nacional.</font></big></font><font   size=\"2\">&nbsp;&nbsp;&nbsp;&nbsp; </font>\n</p>\n\n<p align=\"left\"><font   size=\"2\">Los días de Jueves Santo, Viernes Santo y \nDomingo de Resurrección, Moratalla se convierte en un estruendo. Cada tamborista, que es \nel nombre que recibe el nazareno que toca el tambor, intentará demostrar su \ndestreza, refinamiento y fuerza, así como, la limpieza de sonido de \nsu tambor. El estruendo generado se debe a que cada tamborista hace su toque y no va acompasado con ningún otro, \naunque individualmente es toque es totalmente rítmico. Hay quien dice que esto fue \nlo que se oiría cuando Jesucristo fue crucificado.</font></p>\n\n<p align=\"center\">\n<embed   src=\"../../Asociaciones/Tamboristas/2004/Images/Semana_Santa_2004.swf\"></p>\n\n<p align=\"center\">\n&nbsp;</p>\n\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\"   id=\"AutoNumber1\">\n  <tr>\n    <td >&nbsp;</td>\n    <td ><b><font >\n    <a href=\"Images/tambor3.wav\"><font   size=\"2\">Toque de Tambor Moratallero (6 \n    Seg)</font></a></font></b></td>\n    <td ><a target=\"_self\" href=\"Images/tambor3.wav\">\n    <font   size=\"2\">\n    <img src=\"Images/tamborbo.gif\" alt=\"BEBE1.GIF (10639 bytes)\" border=\"0\"></font></a></td>\n  </tr>\n</table>\n\n<p align=\"center\">\n&nbsp;</p>\n\n<p align=\"left\"><font ><big>&nbsp;&nbsp;&nbsp; </big></font></p>\n', 'ssta_old.htm', '0', '2026-05-07 23:42:45');
INSERT IGNORE INTO `pages` (`id`, `category_id`, `title`, `slug`, `content`, `original_file`, `sort_order`, `created_at`) VALUES ('169', '45', 'SANTO CRISTO', 'santo-cristo-4475', '\n\n<p align=\"center\" >\n    <u>\n    <embed   src=\"Images/xtorayo_1.swf\" align=\"left\" hspace=\"0\"></u><b><font size=\"5\"  >SANTÍSIMO \nCRISTO DEL RAYO</font></b></p>\n<p align=\"center\" ><b>\n<font  size=\"5\" >&nbsp;&nbsp;&nbsp; Desde 1621</font></b></p>\n<p align=\"center\" ><span >\n<a title=\"Programación Mayordamía Santo Cristo 2004\" target=\"_blank\"  href=\"stoxto2004/index.htm\"><font  size=\"4\" > \n    &nbsp;Declarada de interés turístico regional </font></a></span></p>\n<p align=\"center\" >\n    <span >\n    <a title=\"Programación Mayordamía Santo Cristo 2004\" target=\"_blank\"  href=\"stoxto2004/index.htm\">\n    <font   size=\"4\">Del 11 al 17 de Julio</font></a></span></p>\n<p class=\"MsoNormal\" >&nbsp;</p>\n<table border=\"0\" cellpadding=\"0\"   id=\"table1\">\n	<tr>\n		<td><span >\n    	<font  size=\"2\" >\n    	<a target=\"_blank\" href=\"stoxto2004/index.htm\">Fiestas año 2004 (aquí)</a> \n		(</font></span><p><span >\n    	<font  size=\"2\" >\n    	<a target=\"_blank\" href=\"stoxto2005/index.htm\">Fiestas año 2005 (aquí)</a> \n		(</font></span><p><span >\n    	<font  size=\"2\" >\n    	<a target=\"_blank\" href=\"stoxto2006/index.htm\">Fiestas año 2006 (aquí)</a> \n		(</font></span><p><span >\n    	<font  size=\"2\" >\n    	<a target=\"_blank\" href=\"stoxto2007/index.htm\">Fiestas año 2007 (aquí)</a> \n		(</font></span><p><span >\n    	<font  size=\"2\" >\n    	<a target=\"_blank\" href=\"stoxto2008/index.htm\">Fiestas año 2008 (aquí)</a> \n		(</font></span><p>&nbsp;</td>\n		<td>&nbsp;</td>\n	</tr>\n</table>\n<p class=\"MsoNormal\" >\n<span lang=\"ES-TRAD\" >Extraído \ndel libro &quot;Cosas de</span></p>\n<p class=\"MsoNormal\" >\n<span lang=\"ES-TRAD\" >&nbsp;Moratalla&quot; Junio 1915. Ensayo histórico por Don Alfredo \nRubio Heredia, en su 2ª Edición de 1976. Pág.353-362.&nbsp; Este relato fue \nrecopilado por el autor de unas notas escritas por el moratallero D. Emiliano \nMartínez Guillén. </span></p>\n<p class=\"MsoNormal\" align=\"center\" >\n<span lang=\"ES-TRAD\" >I</span></p>\n<p class=\"MsoNormal\" >\n<span lang=\"ES-TRAD\" >A la falda \nde un pequeño cerro, aparecen agrupadas confusamente multitud de casas que se \ntienden en anfiteatro, formando la villa de Moratalla, uno de los pueblos más \nfértiles y sanos de provincia de Murcia. Sus sencillos habitantes recuerdan las \ncostumbres de los moros, cuya dominación sufrieron, al igual del resto de la \nprovincia, especialmente los que habitan en el campo, pues la civilización va \ndesterrando de la población antiguos usos y trajes, armonizándolos con las \ncostumbres de los modernos adelantos. Sus tortuosas y empinadas calles, su \nhermoso Castillo, el sistema de riegos, etc., etc., nos recuerdan aún lo que \nacabamos de exponer.</span></p>\n<p class=\"MsoNormal\" >\n<span lang=\"ES-TRAD\" >&nbsp;</span></p>\n<p class=\"MsoNormal\" >\n<span lang=\"ES-TRAD\" >En dicha \nvilla se venera con exaltación la Imagen del Santísimo Cristo del Rayo, y es \ncostumbre inveterada que; en el momento que algunos nubarrones anuncian la \nproximidad de la tormenta y que la campana da la voz de alarma, con su conocido \nlenguaje, varios mozos del pueblo, en unión del sacerdote nombrado al efecto, \nllevan la Imagen del Cristo a hombro y, poniéndola frente al sitio por donde \naparece la nube, el sacerdote la conjura por medio de rezos y latines. Y sucede \nque unas veces vence el Cristo y la nube huye o se disipa, y otras tienen que \nvolver deprisa a la Iglesia, pues les apedrea de lo firme. Mas siempre hay \ndisculpa para aquellas buenas gentes: si la tormenta arrecia, lo achacan de \nordinario a la falta de carácter y entereza del cura para imponerse a la nube y \nhacerla retroceder. Y recuerdo en este momento y lo cito como modelo de \nsacerdotes enérgicos para conjurar las nubes, al Padre Ludeña, el cual fue \nmuchos años el encargado de dichos conjuros, y era digno de verse el brío y \nvalentía con que desempeñaba su misión; el Padre Ludeña se encaraba con la nube, \nentablando con ella un verdadero pugilato y, después de agotar cuantos latines y \nrezos podían emplearse para contrarrestar y vencer su terrible empuje, si la \nnube seguía avanzando hacia la huerta, haciendo caso omiso de sus enérgicas \nexhortaciones y protestas, aquel hombre, poseído de una agitación y vehemencia \ninconcebibles, echando por su boca cuantos dicterios e interjecciones se pueden \nimaginar contra la nube, la increpaba airadamente, y había que verle si la \ntormenta en sus evoluciones, cambiando de rumbo y sin hacer daño, desaparecía \npor el horizonte... Entonces el buen Padre, que jamás abandonaba su puesto, \nviéndola alejarse la apostrofaba a gritos para que acelerara, si posible fuera, \nsu vertiginosa carrera, y, cuando el arco iris, símbolo de paz y bienandanza, \nlucía sus hermosos y brillantes colores, el Padre Ludeña, arrogante y magnífico, \ncon la satisfacción de la victoria, volvía al pueblo con el bonete echado hacia \natrás, completamente dichoso por haber vencido una vez más a la tormenta, en \nunión al Santísimo Cristo del Rayo. <br>\nMuchas anécdotas podríamos referir, insistiendo sobre el mismo tema; pero nos \nsepararíamos de nuestro objeto, que es la narración de este verídico suceso.\n</span></p>\n<p class=\"MsoNormal\" align=\"center\" >\n<span lang=\"ES-TRAD\" >II</span></p>\n<p class=\"MsoNormal\" >\n<span lang=\"ES-TRAD\" >Era el año \n1621. La Naturaleza, siempre pródiga en este país, derramaba por todas partes \nsus riquezas, convirtiendo la extensa vega en un jardín frondoso, como pudiera \nsoñarse el Paraíso. Las mieses, ya granadas, habían dejado su oscuro color verde \nmar, para convertirse en hilos de oro, que se balanceaban al arrullo de un \nviento perfumado y suave. Los árboles, exuberantes de frondosidad, presentaban \nmuestras de su abundante y próxima cosecha; millares de pájaros de distintas \nclases confundían su eterno cántico de amores. Era la época en que la Naturaleza \nviste siempre sus mejores galas, para hacer entrega al hombre de sus inagotables \ntesoros.</span></p>\n<p class=\"MsoNormal\" >\n<span lang=\"ES-TRAD\" >&nbsp;</span></p>\n<p class=\"MsoNormal\" >\n<span lang=\"ES-TRAD\" >Los \nhermosos días de Junio pasaban, sin que apareciera en el espacio la más pequeña \nmancha que empañara su limpidez. Un viento, ora fuerte, ora suave, ponía en \nmovimiento las capas atmosféricas; contribuyendo, en unión con los rayos \nsolares, a granar las doradas espigas. Ya los mozos del pueblo limpiaban sus \ncortantes hoces y las zagalas se concertaban para ir recogiendo las tronchadas \nespigas abandonadas al levantar los haces de la mies, que más tarde se conducen \na las eras. Por todas partes se notaba animación y alegría.</span></p>\n<p class=\"MsoNormal\" >\n<span lang=\"ES-TRAD\" >&nbsp;</span></p>\n<p class=\"MsoNormal\" >\n<span lang=\"ES-TRAD\" >Amaneció el \nmartes 15 de Junio de 1621, tan despejado y limpio como los anteriores. En la \nIglesia del pueblo se continuaban lentamente las obras de la nueva Parroquia, \nque habían dado principio en el año 1561, y para ello se había derribado parte \nde la antigua; como todavía se puede apreciar por los lados que miran al Norte y \nMediodía, con declinación a Oriente.</span></p>\n<p class=\"MsoNormal\" >\n<span lang=\"ES-TRAD\" >&nbsp;</span></p>\n<p class=\"MsoNormal\" >\n<span lang=\"ES-TRAD\" >Desde \ntiempo inmemorial, existía en la antigua Iglesia la Imagen de Cristo \nCrucificado, y se hallaba colocada en la coronación del altar mayor, que en \naquella época era el que en la actualidad ocupa dicha Imagen, frente al de San \nPedro, por donde entonces tenía su puerta de entrada la Iglesia; todo lo cual \nfue transformándose a medida que avanzaron las obras hasta quedar en la \ndisposición en que hoy existe. </span></p>\n<p class=\"MsoNormal\" >\n<span lang=\"ES-TRAD\" >&nbsp;</span></p>\n<p class=\"MsoNormal\" >\n<span lang=\"ES-TRAD\" >El sol \ntocaba a la mitad de su carrera, se vieron aparecer en el horizonte algunos \ncelajes, semejantes a grandes gasas que; rotas en girones</span><span lang=\"ES-TRAD\" >(sic)</span><span lang=\"ES-TRAD\" > \ninmensos, flotaban en el espacio, juguetes del viento que las impulsaba; el azul \nclarísimo del cielo, lucía más al transparentarse por los caprichoso dibujos que \nen mil cambiantes se formaban y deshacían.</span></p>\n<p class=\"MsoNormal\" >\n<span lang=\"ES-TRAD\" >&nbsp;</span></p>\n<p class=\"MsoNormal\" >\n<span lang=\"ES-TRAD\" >A la sazón \nestábase</span><span lang=\"ES-TRAD\" >(sic)</span><span lang=\"ES-TRAD\" > \ncelebrando en la Iglesia la octava del Santísimo Sacramento, y los fieles \natentos al llamamiento de su cura párroco, el Licenciado Alonso Vadillo, acudían \ncon gran recogimiento a estas prácticas religiosas. El altar mayor que, como \nhemos dicho, era en aquella época el que hoy ocupa el Santo Cristo del Rayo, \nfrente al de San Pedro, había sido adornado con profusión de flores, luces y \nobjetos, por las devotas moratalleras; ya había en el templo infinidad de fieles \ny, entre ellos, Francisco de Ondoño y Justa García su mujer, que conducían un \nniño a cristianar, hijo de Martín Sánchez y de Luisa Martínez, su mujer, y que \nfue bautizado por el Licenciado Jerónimo Moreno, teniente cura de la Parroquia, \nponiéndole el nombre de Pedro, (1) y también estaba entre los concurrentes Ginés \nValero, Regidor del Ayuntamiento y gran devoto del Santísimo Cristo. </span></p>\n<p class=\"MsoNormal\" >\n<span lang=\"ES-TRAD\" >&nbsp;</span></p>\n<p class=\"MsoNormal\" >\n<span lang=\"ES-TRAD\" >Eran las \ntres de la tarde y las campanas daban el último toque, haciendo el llamamiento a \nlos fieles, para las prácticas de la octava que se estaban celebrando; cuando \ncomenzaron a sonar nuevamente, con gran alarma, anunciando la proximidad de una \nnube. Hay que haber nacido en Moratalla, para poder apreciar el efecto que \nproduce el tañido de la campana, anunciando la tormenta. Todo resulta pálido al \ndescribirlo: esos momentos de ansiedad y temor que producen en nuestro ánimo, la \naparición de esas nubes colosales, que parecen grandes montañas arrancadas por \nsu base y movidas por fuerzas sobrenaturales; cuadro imponente, al par que \ngrandioso; aquellas monstruosas figuras, que más bien semejan sueños de la \nfantasía, con esa majestad grandiosa con que se adelantan unas a otras y se las \nvé</span><span lang=\"ES-TRAD\" >(sic)</span><span lang=\"ES-TRAD\" > \ncruzar y confundirse, parecen lejanos pueblos que vienen volando por los aires: \nya imitan llanos inmensos, ya terrenos accidentados y montuosos; otras veces \ntomando formas diversas, ya aparecen a nuestra vista simulando cuerpos \ngigantescos de animales mitológicos, que la imaginación más exaltada y \ncalenturienta no podría concebir.</span></p>\n<p class=\"MsoNormal\" >\n<span lang=\"ES-TRAD\" >&nbsp;</span></p>\n<p class=\"MsoNormal\" >\n<span lang=\"ES-TRAD\" >La campana \nsonaba sin cesar; todos los ánimos esperaban suspensos el resultado de aquel \ninmenso peligro que les amenazaba; tenían confianza en su Santísimo Cristo, pero \ntodavía ningún milagro les había hecho comprender hasta que punto velaba por su \npueblo creyente aquella Imagen a la que con tanto entusiasmo adoraban. Cada vez \nmás lúgubre el tañido de la campana, ponía fríos hasta los huesos; el cielo \noscuro y denso oprimía las cabezas, y el nublado estaba tan bajo que parecía \nhaberse juntado los cielos con la tierra; un solo relámpago brillaba y el \nhorroroso trueno estremecía con su potente sonido hasta las entrañas del \nplaneta; algunas gruesas gotas de agua caían pesadamente, levantando ese olor \ncaracterístico de tierra húmeda que se percibe en las tempestades; el pueblo \nentero confundía sus lamentos con el tenebroso ruido de la tormenta; el espanto \nmás grande se veía en todos los semblantes y las manos crispadas pedían al cielo \nmisericordia y compasión. ¡Cuadro terrible, que estremece hasta el pensarlo, \nofrecían aquellas infelices, encerrados, digámoslo así, en un estrecho círculo, \ndonde impotentes y resignados, esperaban perder vidas y haciendas!... ¡Oh furor \ndesenfrenado y bárbaro de la tempestad!... ¡Manifestación grandiosa del poder \nque encierran los elementos! ¡Oh, relámpago siniestro que nos ciegas y \nenvuelves, tornando del asombro que nos produce tu vivísima luz, al oír vibrante \ntu carcajada satánica que parece mofarse de nuestra timidez!</span></p>\n<p class=\"MsoNormal\" >\n<span lang=\"ES-TRAD\" >&nbsp;</span></p>\n<p class=\"MsoNormal\" >\n<span lang=\"ES-TRAD\" >Todas las \ncalles afluían llenas de gentes que, con lamentos de desesperación y torpe paso, \nluchando con un mar de agua y piedra, con relámpagos y truenos, presurosos \nacudían a la Iglesia, donde se veneraba el Cristo, a pedirle de hinojos amparo y \nprotección; ya no cabían de pie los fieles y sin cesar entraban; pues el mismo \nmiedo y el sobresalto les hacían estrechar más y más las distancias. No se puede \nformar nadie una idea de aquellos momentos de amargura...</span></p>\n<p class=\"MsoNormal\" >\n<span lang=\"ES-TRAD\" >&nbsp;</span></p>\n<p class=\"MsoNormal\" >\n<span lang=\"ES-TRAD\" >La Imagen \naparecía magnifica en lo alto de la coronación del altar mayor, extendiendo su</span><span lang=\"ES-TRAD\" >(sic)</span><span lang=\"ES-TRAD\" > \nbrazos sagrados, como queriendo significar que a todos amparaba por igual; el \nclamoreo incesante de aquel pueblo consternado, sus llantos, las palabras \nentrecortadas a cada momento, aquella confusión de voces angustiosas, pidiendo \nperdón y clemencia, unido al fragoroso ruido de la tempestad, que ya en tales \nmomentos descargaba con furia abrumadora, parecían el último día, la última \nhora, el momento decretado como fin del mundo; ya los ánimos decaían a fuerza de \nsufrir, el desaliento y el abandono se pintaban en sus pálidos semblantes, que \nvolvían con desesperación a todas partes; ni sus ojos vertían lágrimas, ni sus \nbocas exhalaban quejas; sólo, si, temblaban de pies a cabeza; estaban poseídos \nde ese terror contagioso que se apodera de las multitudes en momentos de \npeligro. ¡De pronto un grito unánime y agudo se deja sentir, y la mayor parte de \nlos fieles, deslumbrados, sepultan el rostro entre sus manos!...</span></p>\n<p class=\"MsoNormal\" >\n<span lang=\"ES-TRAD\" >&nbsp;</span></p>\n<p class=\"MsoNormal\" >\n<span lang=\"ES-TRAD\" >En medio \ndel templo, blandiendo como la espada del Angel exterminador, se agitaba con su \nligereza proverbial un rayo que a todos amenazaba aniquilar; parecía sujeto por \nuna fuerza invisible que no le dejaba traspasar el límite que se le había fijado \ny, rugiendo como un espíritu maligno, hacían contorsiones sobrenaturales... \nBreves instantes duró aquella escena aterradora; todos creían llegado su último \nmomento, cuando, veloz, recorriendo el espacio que les separaba, cae cubriendo \nla Imagen del Redentor, que desapareció en medio de aquella encendida hoguera, \nconvertida enseguida en humo denso...</span></p>\n<p class=\"MsoNormal\" >\n<span lang=\"ES-TRAD\" >&nbsp;</span></p>\n<p class=\"MsoNormal\" >\n<span lang=\"ES-TRAD\" >¡Con qué \npalabras se podría hacer comprender lo que pasó en aquel momento sublime, en \nque, despejada la densa niebla, apareció la imagen del Cristo, negra y candente; \npero más hermosa que nunca!... (18)</span></p>\n<p class=\"MsoNormal\" >\n<span lang=\"ES-TRAD\" >&nbsp;</span></p>\n<p class=\"MsoNormal\" >\n<span lang=\"ES-TRAD\" >Había \nperdido por completo su color para no recobrarlo más. El pueblo, humillado, \nentonaba un himno de adoración y de gloria, ¡el himno que se entona cuando habla \nel corazón agradecido!... Aquella potente voz humana, formada por la unión de \ntantas ansias, debió de llegar al cielo, ya que hizo enmudecer hasta el rugido \nde la tempestad!... </span></p>\n<p class=\"MsoNormal\" >\n<span lang=\"ES-TRAD\" >(1)<span >&nbsp;&nbsp;&nbsp;&nbsp;\n</span>En el archivo parroquial y al margen de la partida de bautismo de este \nniño hay puesta la siguiente nota: &quot;Este día y año sucedió el milagro del \nSantísimo Cristo del Rayo&quot;. (N. del A.)</span></p>\n<p class=\"MsoNormal\" >\n<span lang=\"ES-TRAD\" >(18) Por la \nbrillante descripción de las anteriores páginas, podrá deducirse la fe que al \nSSmo. Cristo del Rayo tienen los moratalleros. Desde hace cuatro siglos, no se \nha dejado de hacer todos los años las fiestas en conmemoración del referido \nhecho milagroso. Y eso que la época, a mediados de Junio, no es lo más oportuna \nen un pueblo agrícola, para realizar festejos. Entre éstos, es típico el de las \ncorridas de vacas, que tiene un sabor original; aunque se halle algo reñido con \nlas costumbres cívicas, depuradas y cultas. La dulzaina, la pólvora, los vítores \ny los bailes populares, son también notas de cierto tipismo encantador y \natrayente. (N. del P.)</span></p>\n<p align=\"left\">&nbsp;</p>\n\n<p align=\"left\"><font ><big><font size=\"2\" >&nbsp;&nbsp;&nbsp; \n</font> </big></font></p>\n', 'stoxto.htm', '0', '2026-05-07 23:42:45');
