INSERT IGNORE INTO `pages` (`id`, `category_id`, `title`, `slug`, `content`, `original_file`, `sort_order`, `created_at`) VALUES ('172', '46', 'Fiestas', 'fiestas-8377', '\n\n<p align=\"center\">\n&nbsp;</p>\n\n<table border=\"0\" cellspacing=\"0\" cellpadding=\"0\" border   >\n  <tr>\n    <td  align=\"left\" >\n    <p align=\"center\">\n<embed   src=\"../Images/xtorayo_1.swf\"></p>\n\n<p align=\"center\" ><big>\n<font ><big><big><strong>\n<font size=\"5\">FIESTA SANTÍSIMO CRISTO DEL RAYO</font></strong></big></big></font></big></p> \n\n<p align=\"center\" >\n<font ><strong><big><big><big>\n<font size=\"5\">Comisión de festejos 2004</font></big></big></big></strong></font></p>\n\n<p align=\"center\" ><strong>\n<font  size=\"5\">Peña &quot;FUNDACIÓN BÁRBAROS&quot;</font></strong></p>\n\n<p align=\"center\" >&nbsp;</p>\n\n    </td>\n  </tr>\n  <tr>\n    <td  align=\"center\" >&nbsp;<table border=\"0\" cellspacing=\"0\"  id=\"AutoNumber1\"  border cellpadding=\"0\" >\n      <tr>\n        <td   align=\"left\" valign=\"top\">\n        <table border=\"0\" cellpadding=\"0\" cellspacing=\"0\"  border  id=\"AutoNumber4\" >\n          <tr>\n            <td  colspan=\"2\" >\n        <p align=\"center\"><font size=\"6\"><b>Toros en Moratalla</b></font></p>\n        <p align=\"center\">&nbsp;</p>\n            </td>\n          </tr>\n          <tr>\n            <td  >\n        <embed   src=\"imagen/TOROS_CARTEL2004.swf\" align=\"center\"></td>\n            <td  >\n            <embed   src=\"imagen/TOROS_CARTEL%20MANO2004.swf\" align=\"center\"></td>\n          </tr>\n          <tr>\n            <td   colspan=\"2\" >\n            <p align=\"center\">&nbsp;</p>\n            <p align=\"center\"><b><font >Domingo 11 de Julio de \n            2004. Sensacional becerrada con 4 becerros de la ganadería de D.Juan \n            España de Moratalla.</font></b></p>\n            <p align=\"center\">&nbsp;</td>\n          </tr>\n          <tr>\n            <td  >&nbsp;</td>\n            <td  >&nbsp;</td>\n          </tr>\n          <tr>\n            <td   colspan=\"2\" align=\"center\" >\n            <b><font >RELACIÓN DE VACAS Y TOROS DE LAS FIESTAS</font></b></td>\n          </tr>\n          <tr>\n            <td   colspan=\"2\" align=\"center\">&nbsp;</td>\n          </tr>\n          <tr>\n            <td   colspan=\"2\" align=\"center\">\n            <font ><b>GANADERÍA HERMANOS MERENCIANO RUPERTO (5 \n            vacas)</b></font></td>\n          </tr>\n          <tr>\n            <td  ><font >Nº 6</font></td>\n            <td  ><font >PRESUMIDA</font></td>\n          </tr>\n          <tr>\n            <td  ><font >Nº 11</font></td>\n            <td  ><font >CHAVELA</font></td>\n          </tr>\n          <tr>\n            <td  ><font >Nº 12</font></td>\n            <td  ><font >CARITA</font></td>\n          </tr>\n          <tr>\n            <td  ><font >Nº 25</font></td>\n            <td  ><font >RATITA</font></td>\n          </tr>\n          <tr>\n            <td  ><font >Nº 86</font></td>\n            <td  ><font >AMAPOLA</font></td>\n          </tr>\n          <tr>\n            <td   colspan=\"2\">\n            <p align=\"center\"><font ><b>GANADERÍA D. MARCOS LÓPEZ \n            Y LAS CAÑADAS (7 vacas)</b></font></td>\n          </tr>\n          <tr>\n            <td  ><font >Nº 150</font></td>\n            <td  ><font >GOLONDRINA</font></td>\n          </tr>\n          <tr>\n            <td  ><font >Nº 244</font></td>\n            <td  ><font >CARA REDONDA</font></td>\n          </tr>\n          <tr>\n            <td  ><font >Nº 71</font></td>\n            <td  ><font >SOLA</font></td>\n          </tr>\n          <tr>\n            <td  ><font >Nº 142</font></td>\n            <td  ><font >TERRITORIAL</font></td>\n          </tr>\n          <tr>\n            <td  ><font >Nº 125</font></td>\n            <td  ><font >FLORONCILLA</font></td>\n          </tr>\n          <tr>\n            <td  ><font >Nº 64 </font></td>\n            <td  ><font >CU