      <td  ><font >Nº 30CO</font></td>\n            <td  ><font >AGUILEÑA</font></td>\n          </tr>\n          <tr>\n            <td  ><font >Nº 41V</font></td>\n            <td  ><font >ARISCOSA</font></td>\n          </tr>\n          <tr>\n            <td  ><font >Nº 50 V</font></td>\n            <td  ><font >MORENITA</font></td>\n          </tr>\n          <tr>\n            <td  ><font >Nº 75CO</font></td>\n            <td  ><font >DOMINGUERA</font></td>\n          </tr>\n          <tr>\n            <td  ><font >Nº 206V</font></td>\n            <td  ><font >RETOZONA</font></td>\n          </tr>\n          <tr>\n            <td   align=\"center\" colspan=\"2\">\n            <p ><b><font >\n            GANADERÍA ALICIA CHICO GARCÍA</font></b></p>\n            <p ><b><font >&nbsp;(10 \n            vacas, 5 novillos utreros, 2 toros y 4 novillas)</font></b></p>\n            <p >&nbsp;</td>\n          </tr>\n          <tr>\n            <td   colspan=\"2\">\n            <p  align=\"center\"><b>\n            <font >GANADERÍA EL RELLANO</font></b></p>\n            <p  align=\"center\"><b>\n            <font >&nbsp;(8 vacas)</font></b></p>\n            <p  align=\"center\">&nbsp;</td>\n          </tr>\n          <tr>\n            <td   colspan=\"2\">\n            <p  align=\"center\"><b>\n            <font >GANADERÍA D.ANTONIO FERNÁNDEZ &quot;COFINA&quot;</font></b></p>\n            <p  align=\"center\"><b>\n            <font >&nbsp;(14 vacas)</font></b></p>\n            <p  align=\"center\">&nbsp;</td>\n          </tr>\n          <tr>\n            <td   colspan=\"2\" >\n            <p align=\"center\"><b><font  >En total \n            las fiestas del Santísimo Cristo del Rayo 2004, contarán con 54 \n            vacas, 9 toros, 5 novillas y 5 novillos utreros. 73 reses, así que \n            ojo al canto.</font></b></td>\n          </tr>\n          <tr>\n            <td  >&nbsp;</td>\n            <td  >&nbsp;</td>\n          </tr>\n        </table>\n        <p align=\"