INSERT IGNORE INTO `pages` (`id`, `category_id`, `title`, `slug`, `content`, `original_file`, `sort_order`, `created_at`) VALUES ('174', '46', 'PRINCIPAL', 'principal-7276', '<html>\n\n\n\n\n<head>\n<meta http-equiv=\"Content-Language\" content=\"es\">\n<meta http-equiv=\"Content-Type\" content=\"text/html; charset=windows-1252\">\n<meta name=\"GENERATOR\" content=\"Microsoft FrontPage 5.0\">\n<meta name=\"ProgId\" content=\"FrontPage.Editor.Document\">\n<META NAME=\"Keywords\" CONTENT   =\"Moratalla, Murcia, Turismo, Trieta, Espana, España,cultura, casas rurales, rural, alojamientos,alharabe, benamor, casa cristo, encantada, san jorge, buitre, sabinar, otos, cañada de la cruz, benizar, mazuza, calar de la santa, campo san juan, campo bejar, rogativa, zaen, murtas, nogueras, bajil,  rupestres, rupestre,pinturas, pintura,mediterraneo,banda, rondalla,Pablo Salinas,casas rurales, naturaleza, montaña, campo, monte, pueblo, castillo, iglesia, calles, fiestas, musica, Maria del Carmen Rodriguez Rodriguez, Pablo Salinas Rodriguez, Francisco Salinas Rodriguez\">\n<META NAME=\"Description\" CONTENT=\"Moratalla, Murcia, Turismo, Trieta, Espana, España,cultura, casas rurales, rural, alojamientos,alharabe, benamor, casa cristo, encantada, san jorge, buitre, sabinar, otos, cañada de la cruz, benizar, mazuza, calar de la santa, campo san juan, campo bejar, rogativa, zaen, murtas, nogueras, bajil,  rupestres, rupestre,pinturas, pintura,mediterraneo,banda, rondalla,Pablo Salinas,casas rurales, naturaleza, montaña, campo, monte, pueblo, castillo, iglesia, calles, fiestas, musica, Maria del Carmen Rodriguez Rodriguez, Pablo Salinas Rodriguez, Francisco Salinas Rodriguez\">\n<META NAME=\"Abstract\" CONTENT      =\"Moratalla, Murcia, Turismo, Trieta, Espana, España,cultura, casas rurales, rural, alojamientos,alharabe, benamor, casa cristo, encantada, san jorge, buitre, sabinar, otos, cañada de la cruz, benizar, mazuza, calar de la santa, campo san juan, campo bejar, rogativa, zaen, murtas, nogueras, bajil,  rupestres, rupestre,pinturas, pintura,mediterraneo,banda, rondalla,Pablo Salinas,casas rurales, naturaleza, montaña, campo, monte, pueblo, castillo, iglesia, calles, fiestas, musica, Maria del Carmen Rodriguez Rodriguez, Pablo Salinas Rodriguez, Francisco Salinas Rodriguez\">\n<base target=\"MENU\">\n<style>\n\n</style>\n</head>\n\n<body leftmargin=\"0\" topmargin=\"0\" link=\"#00FF00\" vlink=\"#00FFFF\" alink=\"#FFFFFF\" >\n<table border=\"0\" cellspacing=\"0\" id=\"AutoNumber1\"   cellpadding=\"0\" >\n  <tr>\n    <td   align=\"left\" valign=\"top\">\n    <table border=\"0\" cellpadding=\"0\" cellspacing=\"0\"  id=\"AutoNumber2\"  >\n      <tr>\n        <td  align=\"center\"  valign=\"top\" border >\n    <span ><font ><b>\n    <a href=\"http://www.moratalla-murcia.com\"><font size=\"4\">\n    www.moratalla-murcia.com</font></a> les desea unas muy felices fiestas</b></font></span></td>\n      </tr>\n      <tr>\n        <td  align=\"center\"  valign=\"top\" border >\n    <p >&nbsp;<p ><b>\n    <font  size=\"4\">\n    <span >ALGUNAS NOTICIAS RELACIONADAS CON LA \n    FIESTA</span></font></b></td>\n      </tr>\n      <tr>\n        <td  align=\"center\"  valign=\"top\" border >\n    <p >\n    <a target=\"_blank\" href=\"imagen/himno.pdf\" >\n    <font >Haz clic </font></a><font >\n    <a target=\"_blank\" href=\"imagen/himno.pdf\" >\n    <font >aquí</font></a><a target=\"_blank\" href=\"imagen/himno.pdf\" ><font > \n    y bájate el Himno de Moratalla</font></a></font></p>\n    <p >&nbsp;</td>\n      </tr>\n      <tr>\n        <td  align=\"center\"  valign=\"top\" border >\n    <p ><font ><b>\n    LIBRO DE LAS FIESTAS 2004</b></font></p>\n    <p ><font size=\"2\">Ya está disponible \n    por <b>10 €uros</b>, en cualquier kiosco o librería, desde el día 3 de Julio \n    de 2004.</font><p ><font size=\"2\">\n    Cómpralo lleva una sorpresa dentro muy interesante.</font></td>\n      </tr>\n      <tr>\n        <td  align=\"center\"  valign=\"top\" border >\n    <p ><font ><b>\n    NOVILLADA SIN CABALLOS</b></font></p>\n    <p ><font size=\"2\">El día 11 de Julio \n    de 2004, novillada sin caballos a cargo de los alumnos de la escuela \n    taurina.</font></td>\n      </tr>\n      <tr>\n        <td  align=\"center\"  valign=\"top\" border >\n    <p ><b>MANO A MANO</b></p>\n    <p ><font size=\"2\" >El \n    día 10 de Julio de 2004, mano a mano entre los diestros </font></p>\n    <p ><b><font >Pepín \n    Liria y Antonio José López &quot;El Rubio&quot;</font></b></td>\n      </tr>\n      <tr>\n        <td  align=\"center\"  valign=\"top\" border >\n    <p ><b><font >XIX \n    PREMIO PEÑA &quot;EL ZAQUE&quot;</font></b></p>\n    <p ><font size=\"2\">El día 3 de Julio \n    de 2004, la Asociación Cultural Peña &quot;El Zaque&quot; entregó&nbsp; XIX PREMIO \n    PEÑA &quot;EL ZAQUE&quot;, en el teatro Trieta, en esta edición el premiado fue \n    Antonio Fernández &quot;COFINA&quot;,&nbsp; esta familia de ganaderos traen reses \n    bravas a Moratalla desde 1939, casi na 65 años pa\'habernos matao</font></td>\n      </tr>\n      <tr>\n        <td  align=\"center\"  valign=\"top\" border >\n            <p align=\"center\" >\n    <b>La <font >RONDALLA TRIETA</font> de Moratalla</b><p align=\"center\" >\n    <font size=\"2\">estuvo de ronda la noche del día 8 de Junio de 2004, deleiteando \n    a nuestras damas de honor con sus espléndidas músicas y cantares. Gracias \n    por tan magnífica velada.</font></td>\n      </tr>\n      <tr>\n        <td  align=\"center\"  valign=\"top\" border >\n    <p ><b>\n    <font >XXXVI Certamen Literario &quot;Albaricoque de Oro&quot;\n    </font></b></p>\n    <p ><b>\n    <font  size=\"2\">El día 3 Julio de 2004, en la Velada \n    Literaria que tendrá lugar en el Teatro Trieta, se hará público el fallo del \n    Jurado. </font></b></p>\n    <p  align=\"left\">\n    <b>\n    <font  size=\"2\">Tema local, referido a Moratalla.</font></b></p>\n    <p  align=\"right\">\n    <b>\n    <font  size=\"2\">Un primer premio en Verso </font></b></p>\n    <p  align=\"right\">\n    <b>\n    <font  size=\"2\">Un primer premio en Prosa</font></b></p>\n    <p  align=\"left\">\n    <b>\n    <font  size=\"2\">Tema libre.</font></b></p>\n    <p  align=\"right\">\n    <b>\n    <font  size=\"2\">Un primer premio en Verso </font></b></p>\n    <p  align=\"right\">\n    <b>\n    <font  size=\"2\">Un primer premio en Prosa</font></b></p>\n    <p  align=\"left\"><b>\n    <font  size=\"2\">El plazo de presentación de trabajos finalizó \n    el 5 de Junio de 2004</font></b></p>\n    <p  align=\"left\">\n    <font size=\"2\" ><b>Organizado por :</b></font></p>\n    <p  align=\"right\">\n    <font size=\"2\" ><b>Iltmo. Ayuntamiento de Moratalla </b>\n    </font></p>\n    <p  align=\"right\">\n    <font size=\"2\" ><b>Comisión de festejos Santísimo Cristo de \n    Rayo &quot;Fundación Bárbaros&quot;</b></font></td>\n      </tr>\n      <tr>\n        <td  align=\"left\" valign=\"top\"  border >\n    &nbsp;</td>\n      </tr>\n      </table>\n    </td>\n    <td   align=\"left\" valign=\"top\">\n    &nbsp;', 'PRINCIPAL.htm', '0', '2026-05-07 23:42:45');
INSERT IGNORE INTO `pages` (`id`, `category_id`, `title`, `slug`, `content`, `original_file`, `sort_order`, `created_at`) VALUES ('175', '46', 'Fiestas', 'fiestas-2871', '\n\n<p align=\"center\">\n&nbsp;</p>\n\n<table border=\"1\" cellspacing=\"0\" cellpadding=\"0\" border   >\n  <tr>\n    <td  align=\"left\" >\n    <p align=\"center\">\n<font >\n<embed   src=\"../Images/xtorayo_1.swf\"></font></p>\n\n<p align=\"center\" ><big>\n<font  ><big><big><strong>\n<font size=\"4\">FIESTA SANTÍSIMO CRISTO DEL RAYO</font></strong></big></big></font></big></p> \n\n<p align=\"center\" >\n<font  ><strong><big><big><big>\n<font size=\"4\">Comisión de Festejos 2004</font></big></big></big></strong></font></p>\n\n<p align=\"center\" ><strong>\n<font  size=\"4\" >Peña &quot;FUNDACIÓN BÁRBAROS&quot;</font></strong></p>\n\n<p align=\"center\" ><font >\n<embed   src=\"../Images/logo_barbaros.swf\"></font></p>\n\n<p align=\"center\" >&nbsp;</p>\n\n    </td>\n  </tr>\n  <tr>\n    <td  align=\"center\"  >\n    <p >\n    <font  size=\"2\" ><strong>\n    <a target=\"Central\" title=\"Representantes MAYORDOMÍA de SANTO CRISTO 2004\" href=\"mayor2004.htm\" >\n    <font >Miembros  \n    de la Mayordomía del Santísimo Cristo del Rayo 2004 </font></a></strong></font>\n    <p >\n    <font  size=\"2\" ><strong>\n    <a target=\"Central\" title=\"Representantes MAYORDOMÍA de SANTO CRISTO 2004\" href=\"mayor2004.htm\" >\n    <font >Peña &quot;FUNDACIÓN  \n    BÁRBAROS&quot;</font></a></strong></font></td>\n  </tr>\n  <tr>\n    <td  align=\"center\" >\n    <p >\n    <font  size=\"2\" ><strong>ORDEN DE FESTEJOS \n    FIESTAS SANTÍSIMO CRISTO DE RAYO 2004</strong></font></td>\n  </tr>\n  <tr>\n    <td  align=\"center\"  >\n    <p ><font ><b>DAMAS DE \n    HONOR Y&nbsp; REINA DE LAS FIESTAS</b></font></td>\n  </tr>\n  <tr>\n    <td  align=\"center\" >\n    <p ><font ><b>\n    CONCIERTOS</b></font></td>\n  </tr>\n  <tr>\n    <td  align=\"center\"  >&nbsp;</td>\n  </tr>\n  <tr>\n    <td  align=\"center\"  >\n    <p >\n    <font  size=\"2\" ><strong>\n    <a title=\"Correo Electrónico de Contacto\" href=\"mailto:f_barbaros@wanadoo.es;santana@wanadoo.es?subject=Desde www.moratalla-murcia.com\" >\n    <font >Correo \n    electrónico de contacto, para cualquier sugerencia o crítica, además se \n    pueden enviar aportaciones en texto o fotografía, para su posible \n    incorporación en el libro de la Fiestas.</font></a></strong></font></td>\n  </tr>\n  </table>\n\n<p align=\"center\">&nbsp;</p>\n\n', 'STOXTO2004.HTM', '0', '2026-05-07 23:42:45');
