tas, nogueras, bajil,  rupestres, rupestre,pinturas, pintura,mediterraneo,banda, rondalla,Pablo Salinas,casas rurales, naturaleza, montaña, campo, monte, pueblo, castillo, iglesia, calles, fiestas, musica, Maria del Carmen Rodriguez Rodriguez, Pablo Salinas Rodriguez, Francisco Salinas Rodriguez\">\n<base target=\"MENU\">\n<style>\n\n</style>\n</head>\n\n<body leftmargin=\"0\" topmargin=\"0\" link=\"#00FF00\" vlink=\"#00FFFF\" alink=\"#FFFFFF\" >\n<table border=\"0\" cellspacing=\"0\" id=\"AutoNumber1\"   cellpadding=\"0\" >\n  <tr>\n    <td   align=\"left\" valign=\"top\">\n    <table border=\"0\" cellpadding=\"0\" cellspacing=\"0\"  id=\"AutoNumber2\"  >\n      <tr>\n        <td  align=\"center\"  valign=\"top\" border >\n    <span >\n	<font  ><b>\n    <a href=\"http://www.moratalla-murcia.com\">www.moratalla-murcia.com</a> les desea unas muy felices fiestas 2006</b></font></span></td>\n      </tr>\n      <tr>\n        <td  align=\"center\"  valign=\"top\" border >\n    <p >&nbsp;<p ><b>\n    <font  size=\"1\" >\n    <span >ALGUNAS NOTICIAS RELACIONADAS CON LA \n    FIESTA</span></font></b></td>\n      </tr>\n      <tr>\n        <td  align=\"center\"  valign=\"top\" border >\n    <p >\n    &nbsp;</p>\n	<p >\n    <img border=\"0\" src=\"../stoxto2006/imagen/gr/POYO.jpg\"  ></p>\n	<p >\n    &nbsp;</p>\n	<p >\n    <font   size=\"2\">\n	<a target=\"_blank\" href=\"../stoxto2006/imagen/himno.pdf\" >\n    Haz clic </a>\n    <a target=\"_blank\" href=\"../stoxto2006/imagen/himno.pdf\" >\n    <font >aquí</font></a><a target=\"_blank\" href=\"../stoxto2006/imagen/himno.pdf\" ><font > \n    y bájate el Himno de Moratalla</font></a></font></p>\n    	</td>\n      </tr>\n      <tr>\n        <td  align=\"center\"  valign=\"top\" border >\n    <p >\n	<font   size=\"2\"><b>\n    LIBRO DE LAS FIESTAS 2006</b></font></p>\n    <p ><font size=\"2\" >Ya está disponible \n    en cualquier kiosco o librería, desde el día 1 de Julio \n    de 2006.</font></td>\n      </tr>\n      <tr>\n        <td  align=\"center\"  valign=\"top\" border >\n            <p align=\"center\" >\n    &nbsp;<p align=\"center\" >\n    <font  size=\"2\"><b>La <font >RONDALLA TRIETA</font> de Moratalla</b></font><p align=\"center\" >\n    <font size=\"2\" >estuvo de ronda la noche del día 8 de Junio de 2006, \n	ofreciendo sus serenatas \n    a nuestras damas de honor. </font>\n	<p align=\"center\" >\n    <font size=\"2\" >Gracias \n    por vuestro espíritu alegre.</font></td>\n      </tr>\n      <tr>\n        <td  align=\"center\"  valign=\"top\" border >\n    &nbsp;<p>\n	<img border=\"0\" src=\"../stoxto2006/imagen/gr/MANSOS.jpg\"  ></p>\n	<p>&nbsp;</td>\n      </tr>\n      <tr>\n        <td  align=\"center\"  valign=\"top\" border >\n    &nbsp;</td>\n      </tr>\n      <tr>\n        <td  align=\"center\"  valign=\"top\" border >\n            &nbsp;</td>\n      </tr>\n      <tr>\n        <td  align=\"center\"  valign=\"top\" border >\n    &nbsp;</td>\n      </tr>\n      <tr>\n        <td  align=\"left\" valign=\"top\"  border >\n    &nbsp;</td>\n      </tr>\n      </table>\n    </td>\n    <td   align=\"left\" valign=\"top\">\n    &nbsp;</table>\n<p>&nbsp;</p>', 'PRINCIPAL.htm', '0', '2026-05-07 23:42:46');
