INSERT IGNORE INTO `pages` (`id`, `category_id`, `title`, `slug`, `content`, `original_file`, `sort_order`, `created_at`) VALUES ('272', '100', 'Pagina nueva 1', 'pagina-nueva-1-4400', '\n\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\"  border  id=\"AutoNumber1\">\n  <tr>\n    <td >\n    <p  align=\"justify\"><b>\n    <font >Viernes 2 de Julio de 2004.</font></b></p>\n    <p  align=\"justify\"><b>\n    <font >20:30 H.</font></b></p>\n    <p  align=\"justify\"><b>\n    <font  size=\"4\">SALÓN DE ACTOS DEL AYUNTAMIENTO.</font></b></p>\n    <p  align=\"justify\"><b>\n    <font  size=\"4\">MESA DE DEBATE:</font></b></p>\n    <p  align=\"justify\">\n    <font >* Memoria de lo sucedido en julio de 1994.</font></p>\n    <p  align=\"justify\">\n    <font >* Análisis de actuaciones sobre el espacio quemado y \n    las restantes masas forestales.</font></p>\n    <p  align=\"justify\">\n    <font >* Propuestas de actuación.</font></p>\n    <p  align=\"justify\"><b>\n    <font >CON LA PARTICIPACIÓN DE :</font></b></p>\n    <p  align=\"justify\">\n    <font >Profesores de la Universidad de Murcia, técnicos de la \n    administración ambiental, forestal y de protección civil.</font></p>\n    <p  align=\"justify\">&nbsp;</p>\n    <p  align=\"justify\"><b>\n    <font  size=\"4\">&quot;Imágenes para la memoria&quot;</font></b></p>\n    <p  align=\"justify\">\n    <font >Exposición de fotografía en la sala del Convento de \n    San Francisco.</font></p>\n    <p  align=\"justify\"><b>\n    <font >Desde el sábado 3 al viernes 9 de julio de 2004.</font></b></p>\n    <p  align=\"justify\"><b>\n    <font >Horas de visita: tardes de 7 a 10.</font></b></p>\n    <p  align=\"justify\">&nbsp;</p>\n    <p  align=\"justify\"><b>\n    <font >Domingo, 4 de Julio de 2004.</font></b></p>\n    <p  align=\"justify\"><b>\n    <font >20:00 H.</font></b></p>\n    <p  align=\"justify\"><b>\n    <font  size=\"4\">PLAZA DEL AYUNTAMIENTO.</font></b></p>\n    <p  align=\"justify\"><b>\n    <font  size=\"4\">Cinco minutos de silencio. &quot;NUNCA MÁS&quot;</font></b></p>\n    <p  align=\"justify\">&nbsp;</p>\n    <p  align=\"justify\"><b>\n    <font >Domingo, 4 de Julio de 2004.</font></b></p>\n    <p  align=\"justify\"><b>\n    <font >20:30 H.</font></b></p>\n    <p  align=\"justify\"><b>\n    <font  size=\"4\">SALÓN DE ACTOS DEL AYUNTAMIENTO.</font></b></p>\n    <p  align=\"justify\"><b>\n    <font  size=\"4\">MESA DE DEBATE:</font></b></p>\n    <p  align=\"justify\">\n    <font >* Memoria de lo sucedido en julio de 1994.</font></p>\n    <p  align=\"justify\">\n    <font >* Análisis de actuaciones sobre el espacio quemado y \n    las restantes masas forestales.</font></p>\n    <p  align=\"justify\">\n    <font >* Propuestas de actuación.</font></p>\n    <p  align=\"justify\"><b>\n    <font >CON LA PARTICIPACIÓN DE:</font></b></p>\n    <p  align=\"justify\">\n    <font >Representantes de los diversos partidos políticos y \n    grupos ecologistas.</font></td>\n  </tr>\n</table>\n\n', 'Actos apenas10.htm', '0', '2026-05-07 23:42:50');
INSERT IGNORE INTO `pages` (`id`, `category_id`, `title`, `slug`, `content`, `original_file`, `sort_order`, `created_at`) VALUES ('273', '83', 'SANTO CRISTO', 'santo-cristo-9414', '\n\n<p align=\"center\" >\n    <b><font size=\"5\"  >NOTICIAS DE MORATALLA</font></b></p>\n<p align=\"center\" >\n    <b><font  size=\"5\" >AÑO 2004</font></b></p>\n<p class=\"MsoNormal\" >&nbsp;</p>\n<table border=\"1\" cellpadding=\"0\"   id=\"table1\" border>\n	<tr>\n        <td  align=\"center\" >\n    <p  dynamicanimation=\"fpAnimOutflyBottomRightFP1\" id=\"fpAnimOutflyBottomRightFP1\" ondblclick=\"dynAnimOut(this)\" language=\"Javascript1.2\">\n    <font ><b>\n    <a target=\"_blank\" href=\"apenas10/Actos%20apenas10.htm\">\n    <img border=\"0\" src=\"apenas10/apenas10.jpg\" align=\"left\"  ></a></b></font></p>\n    <p  align=\"right\"><b>\n    <span ><font size=\"2\">\n    <a target=\"_blank\" href=\"apenas10/Actos%20apenas10.htm\" >\n    <font >Jornadas para la memoria, el análisis y la propuesta</font></a></font></span></b></p>\n    <p align=\"justify\" ><b>\n    <font  size=\"2\">\n    <a target=\"_blank\" href=\"apenas10/Actos%20apenas10.htm\" >\n    <font >Lunes, 4 de julio de 1994: comienza el mayor incendio \n    forestal del que existe constancia en la Historia de España. Durante cinco \n    días, el fuego devora, implacable, más de 30000 Hectáreas.</font></a></font></b></p>\n    <p align=\"justify\" ><b>\n    <font  size=\"2\">\n    <a target=\"_blank\" href=\"apenas10/Actos%20apenas10.htm\" >\n    <font >Desde Moratalla se extiende hacia toda nuestra región \n    una ola de estupor y rabia ante un desastre de tan gigantescas proporciones.</font></a></font></b></td>\n      </tr>\n	<tr>\n        <td  align=\"center\" >\n    <p  align=\"left\"><font ><b><font size=\"2\">PRESENTACIÓN \n    DEL LIBRO</font></b><font size=\"2\">: ( En dos volúmenes)</font></font></p>\n    <p  align=\"center\"><b>\n    <font  size=\"4\">MORATALLA, A TRAVÉS DE LOS TIEMPOS</font></b></p>\n    <p  align=\"center\"><b>\n    <font >Historia de una villa santiaguista en el Reino de \n    Murcia.</font></b></p>\n    <p  align=\"center\"><b>\n    <font  size=\"2\">AUTOR: MARCIAL GARCÍA GARCÍA</font></b></p>\n    <p >\n    <font  size=\"2\" >El libro fue presentado el día 20 de febrero de \n    2004, por el periodista Kiko Medina, en el salón de actos del Ayuntamiento \n    de Moratalla, con gran afluencia de público.</font><p >\n    <font  size=\"2\"><b>Nota del Webmaster</b>: <b><font >\n    Yo los estoy leyendo y todo moratallero debería tener y leer esta obra. \n    Enhorabuena Marcial y gracias por mostrarnos nuestro pasado y abrir puertas \n    al futuro.</font></b></font></td>\n      </tr>\n	<tr>\n        <td  align=\"center\" >\n    <p  align=\"justify\"><font size=\"2\">\n    <img border=\"0\" src=\"../cultura/Arqueologia/images/logo_rupestre_peque.gif\"   align=\"left\">El \n    día 21 de Diciembre de 2003, se celebraron en el <b>Calar de la Santa</b> y \n    organizadas por el <b>Ilmo. Ayuntamiento de Moratalla</b>, las <b>I Jornadas \n    de Difusión del Arte Rupestre de Moratalla</b>. Consideradas <b>Patrimonio \n    de la Humanidad por la UNESCO</b>, son la mayor aglomeración de pinturas \n    rupestres del arco mediterráneo. </font></p>\n    <p align=\"right\" ><font size=\"2\">\n    <a target=\"_blank\" href=\"../cultura/Arqueologia/I_JORNADA_RUPESTRE1.pdf\" >\n    <font >Ampliar información</font></a></font></td>\n      </tr>\n</table>\n', 'noticias2004.htm', '0', '2026-05-07 23:42:50');
INSERT IGNORE INTO `pages` (`id`, `category_id`, `title`, `slug`, `content`, `original_file`, `sort_order`, `created_at`) VALUES ('274', '83', 'SANTO CRISTO', 'santo-cristo-3794', '\n\n<p align=\"center\" >\n    <b><font size=\"5\"  >NOTICIAS DE MORATALLA</font></b></p>\n<p align=\"center\" >\n    <b><font  size=\"5\" >AÑO 2005</font></b></p>\n<table border=\"1\" cellpadding=\"0\"   id=\"table1\" border>\n	<tr>\n        <td  align=\"center\" >\n		<table border=\"1\" cellspacing=\"1\"  border  id=\"table2\" >\n			<tr>\n				<td   >\n				<p  align=\"center\">\n				<font  size=\"4\"><b>\n				<img border=\"0\" src=\"librojoaquin/LA-VIDA-UN-EXODO_W.jpg\"   align=\"left\"></b></font></p>\n				<p class=\"MsoNormal\"  align=\"center\">\n				<font >\n				<span >\n				PRESENTACIÓN </span></font></p>\n				<p class=\"MsoNormal\"  align=\"center\">\n				<font >\n				<span >VIERNES, 3 \n				DE JUNIO DE 2005</span></font></p>\n				<p class=\"MsoNormal\"  align=\"center\">\n				<font >\n				<span >A LAS 21:00\n				</span></font></p>\n				<p class=\"MsoNormal\"  align=\"center\">\n				<font >\n				<span >SALÓN DE \n				ACTOS DEL AYUNTAMIENTO DE MORATALLA</span></font></p>\n				<p class=\"MsoNormal\"  align=\"center\">\n				<span >\n				<font size=\"4\" >LA VIDA, UN ÉXODO</font></span></p>\n				<p class=\"MsoNormal\"  align=\"center\">\n				<span >\n				<font size=\"4\" >Joaquín Sánchez Sánchez</font></span></p>\n				<p class=\"MsoNormal\"  align=\"center\">\n				<span ><font size=\"1\">ISBN: 84-609-4293-7. \n		Dep. Legal: MU-2.262-2004</font></span></p>\n				<p class=\"MsoNormal\" >&nbsp;</p>\n				<p class=\"MsoNormal\" >\n				<font >\n				<span >PRÓLOGO de<b> LA VIDA, UN ÉXODO.</b></span></font></p>\n				<p class=\"MsoNormal\" >&nbsp;</p>\n				<p class=\"MsoNormal\" >\n				<font >\n				<span >Si tuviera que definir la actitud ante la vida, las \n		palabras más adecuadas serían “<b>compromiso con la propia vida</b>”. Un \n		compromiso que se traduce en una constante búsqueda de la verdad, un \n		compromiso que se expresa en la fidelidad por conseguir una existencia \n		sin miedos ni amenazas ni chantajes, un compromiso por vivificar la \n		vida, por dar vida a la propia vida.</span></font></p>\n				<p class=\"MsoNormal\" >\n				<font >\n				<span >&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; ………….</span></font></p>\n				<p class=\"MsoNormal\" >\n				<font >\n				<span >&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Este libro quiere ser una llamada a vivir y a \n		convivir desde la reflexión crítica del momento presente. Quiere ser una \n		invitación a creer en la utopía para decir <b>SÍ A LA VIDA<span >.</span></b></span></font></p>\n				<p class=\"MsoNormal\" >\n				<font >\n				<span >&nbsp;</span></font></p>\n				<p class=\"MsoNormal\" >\n				<font >\n				<span >Así comienza y \n		termina el prólogo de este ameno libro, escrito por Joaquín Sánchez \n		Sánchez, usando un lenguaje al alcance de todos, nos expone pensamientos \n		que de seguro a todos nos habrán pasado alguna vez por la cabeza, pero \n		que nunca o casi nunca nos hemos atrevido a expresar desde un \n		pensamiento crítico, libre de las interferencias del entorno donde nos \n		movemos. </span></font></p>\n				<p class=\"MsoNormal\" >\n				<font >\n				<span >&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; <b>Joaquín Sánchez Sánchez</b>, es natural de \n		Bullas, durante algunos años vivió en Moratalla, donde tuve el honor de \n		conocerle y ser su amigo, junto a otros moratalleros. Actualmente es \n		párroco en Las Torres de Cotillas, y desde que lo conozco siempre a \n		estado del lado de los más desfavorecidos de nuestra sociedad, por todo \n		esto, desde esta humilde página web que habla de nuestro pueblo es para \n		mí un privilegio felicitarle por su primer libro.</span></font><p class=\"MsoNormal\" >&nbsp;</td>\n			</tr>\n			<tr>\n				<td   >\n				<font  size=\"2\">La </font><b><font >\n				Asociación para la defensa de la naturaleza </font></b>\n				<font ><b>CARALLUMA</b></font><font  size=\"2\"> \n				se integra en la<b> </b></font><b>\n				<font  >plataforma &quot;Murcia no se \n				Vende&quot;</font></b><font  size=\"2\">, formada por más \n				de 30 colectivos de la Región de Murcia. El </font><b>\n				<font  >próximo día 4 de Junio de \n				2005 a las 7 de la tarde tendrá lugar una manifestación el la \n				Plaza de Santo Domingo</font></b><font  size=\"2\">, \n				en contra del actual modelo de desarrollo urbanístico, que ha \n				hecho que la Región de Murcia se degrade ambientalmente en los \n				últimos años, no teniendo en cuenta el impacto medioambiental y la \n				explotación de los pocos acuíferos de la región.&nbsp; </font></td>\n			</tr>\n		</table>\n		</td>\n      </tr>\n	<tr>\n        <td  align=\"center\" >\n    &nbsp;</td>\n      </tr>\n	</table>\n', 'noticias2005.htm', '0', '2026-05-07 23:42:50');
