INSERT IGNORE INTO `pages` (`id`, `category_id`, `title`, `slug`, `content`, `original_file`, `sort_order`, `created_at`) VALUES ('305', '139', 'Ana María Almagro', 'ana-maria-almagro', '\n<div class=\"legacy-content\">\n    <p><strong>Ana Mª Almagro</strong>, pintora artística, viene dedicando su creatividad a trabajos sobre seda y a pastel, fundamentalmente, creación que queda reflejada en cuadros de muy diversos y variados temas, algunos de ellos, de grandes dimensiones.</p>\n    <p>Pero también esa creación e inquietud la transmite a pañuelos y corbatas, en los que el blanco inmaculado de la seda, ha dado paso a una explosión de color siempre unida íntimamente al diseño único y exclusivo de cada una de sus prendas.</p>\n    <p>Es la autora de la pintura mural en el arco central del presbiterio de la Ermita de Santa Ana, así como de otros murales a tamaño natural para particulares. Igualmente, es autora del estandarte de Jesucristo Aparecido y de la Santa Faz que lleva La Verónica en la escenificación del Vía Crucis por las calles de Moratalla.</p>\n</div>', NULL, '0', '2026-05-08 12:57:05');
INSERT IGNORE INTO `pages` (`id`, `category_id`, `title`, `slug`, `content`, `original_file`, `sort_order`, `created_at`) VALUES ('306', '140', 'Bartolomé Marín Rubio', 'bartolome-marin-rubio', '\n<div class=\"legacy-content\">\n    <p><strong>Bartolomé Marín Rubio</strong>, conocido cariñosamente como <strong>\"EL GRANADOS\"</strong>, fue un insigne artesano de Moratalla dedicado al noble oficio del esparto.</p>\n    <p>A través de sus manos, el esparto cobraba vida en forma de útiles tradicionales, aperos y objetos decorativos que forman parte del patrimonio cultural de nuestra tierra. Su destreza y dedicación son un ejemplo de la artesanía viva que define a Moratalla.</p>\n    <p>Esta sección es un reconocimiento a su trayectoria y a su legado, manteniendo viva la memoria de las tradiciones que nos dan identidad.</p>\n    <div class=\"legacy-note\">\n        <p><em>Contenido restaurado de la web original - Homenaje a \"Mi Abuelo\"</em></p>\n    </div>\n</div>', NULL, '0', '2026-05-08 13:01:05');
